INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1602, 16, 1, 'Foundations of Intellectual Property: History and Core Concepts', 'Explore the historical origins of intellectual property rights, from ancient times to the modern era, and understand the fundamental concepts that underpin IP protection. This week establishes why societies recognize and protect intellectual creations.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1603, 16, 2, 'Types of Intellectual Property: Patents, Trademarks, Copyrights, and Trade Secrets', 'Examine the distinct categories of intellectual property protection, including their specific purposes, scope, and real-world applications. Learn how different IP mechanisms protect different types of intellectual creations.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (193, 36, 1, 'Foundations of Tech Entrepreneurship', 'Explore the fundamental concepts of tech entrepreneurship, understanding the startup ecosystem, and developing an entrepreneurial mindset. Students will learn about different types of tech businesses and the key characteristics of successful tech entrepreneurs.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (194, 36, 2, 'Identifying and Validating Tech Opportunities', 'Learn how to recognize market gaps, conduct market research, and validate business ideas through customer discovery and lean startup methodologies. Students will develop skills in problem identification and initial concept testing.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (195, 36, 3, 'Business Model Design and Innovation', 'Deep dive into creating robust business models using tools like the Business Model Canvas, understanding revenue streams, value propositions, and developing a sustainable business strategy for tech ventures.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (196, 36, 4, 'Tech Startup Funding and Financial Planning', 'Explore funding strategies for tech startups, including bootstrapping, venture capital, angel investing, and crowdfunding. Learn how to create financial projections and pitch to potential investors.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1604, 16, 3, 'Global IP Systems: International Frameworks and Cultural Perspectives', 'Investigate international IP treaties, conventions, and the varying approaches to IP protection across different countries and cultures. Understand how globalization and cultural values shape intellectual property systems worldwide.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1605, 16, 4, 'IP Enforcement and Practical Implementation: From Strategy to Litigation', 'Study the mechanisms for registering, protecting, and enforcing intellectual property rights, including licensing, infringement detection, and dispute resolution. Synthesize all concepts to understand real-world IP management and strategic considerations.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2481, 17, 1, 'Classical Foundations of Educational Philosophy', 'Discover how Plato, Aristotle, and Rousseau shaped our understanding of education''s purpose - from philosopher-kings to natural learning.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2482, 17, 2, 'Modern Philosophy: Democracy and Liberal Education', 'Explore Dewey''s vision of education for democracy and Newman''s defense of liberal education as cultivation of mind.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (15, 11, 1, 'Understanding the AI Revolution', 'Explore the history and evolution of large language models from transformers to GPT-4. Understand how these models work at a conceptual level and why they represent a paradigm shift in technology.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (16, 11, 2, 'AI Tools for Product Workflows', 'Survey the landscape of AI tools available to product builders. Learn to evaluate AI assistants and understand their capabilities and limitations and integrate them into your daily workflow.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (17, 11, 3, 'Building AI-Enhanced Products', 'Learn frameworks for incorporating AI into product design. Understand prompt engineering basics and API integration patterns and how to design user experiences around AI capabilities.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (18, 11, 4, 'AI Product Strategy & Ethics', 'Develop strategic thinking about AI product development. Consider ethical implications and bias and responsible AI practices while building products that leverage these powerful technologies.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2483, 17, 3, 'The Evolution of Educational Institutions', 'Trace the development from Plato''s Academy through medieval universities to understand how curriculum and institutions evolved.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2484, 17, 4, 'Technology and the Democratization Question', 'Critically examine whether MOOCs and platforms like Khan Academy have fulfilled their promise to democratize education.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2232, 24, 1, 'Retirement Savings Foundations', 'Introduction to retirement planning and understanding the basics of saving for the future') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2233, 24, 2, 'Investment Strategies for Retirement', 'Deep dive into retirement investment approaches, understanding risk, and building a diversified portfolio') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (23, 13, 1, 'Typography Essentials', 'Master the art of selecting and arranging type. Learn font anatomy and hierarchy and pairing and spacing to create readable and visually appealing text layouts.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (24, 13, 2, 'Color Theory & Application', 'Understand the color wheel and color harmonies and color psychology. Learn to create effective color palettes that communicate the right message and evoke desired emotions.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (25, 13, 3, 'Layout & Composition', 'Learn principles of visual hierarchy and grid systems and alignment and spacing. Understand how to guide the viewers eye and create balanced engaging compositions.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (26, 13, 4, 'Design in Practice', 'Apply all design principles together in real projects. Create cohesive designs that combine typography and color and layout into professional visual communications.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2234, 24, 3, 'Advanced Retirement Planning and Risk Management', 'Exploring complex retirement planning strategies, tax optimization, and comprehensive financial risk management') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2235, 24, 4, 'Retirement Planning Integration and Action', 'Synthesizing learnings, creating a comprehensive retirement plan, and developing a sustainable financial future strategy') ON CONFLICT DO NOTHING;
