INSERT INTO weeks (id, binder_id, index, title, description) VALUES (197, 36, 5, 'Launch Strategies and Scaling Your Tech Venture', 'Synthesize previous learnings into a comprehensive launch strategy, focusing on minimum viable product (MVP) development, go-to-market approaches, and initial scaling techniques for tech entrepreneurs.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (298, 26, 1, 'Origins of Cinematography: The Early 20th Century', 'Explore the foundational history of cinematography, understanding its technological and cultural origins in the early 20th century.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (299, 26, 2, 'Innovations and Artistry: Digital Cinematography Emergence', 'Explore the transformative shift from traditional film to digital cinematography, understanding the technological innovations that reshaped visual storytelling in the late 20th century.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (300, 26, 3, 'Digital Frontiers: Cinematography in the Contemporary Era', 'Explore the transformative impact of digital technologies on cinematography, examining how new tools and techniques are reshaping visual storytelling in the 21st century.') ON CONFLICT DO NOTHING;
