INSERT INTO weeks (id, binder_id, index, title, description) VALUES (361, 10, 1, 'Foundations: Vibe Coding vs AI-Assisted Engineering', 'Understand the spectrum from casual vibe coding to production-grade AI-assisted development. Learn the mental models and workflows and critical judgment calls that separate productive AI-assisted development from frustrating guesswork.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (362, 10, 2, 'Design Tokens & CSS Variables', 'Master the foundational layer of design-code alignment. Learn how to structure design tokens and naming conventions and CSS variables that AI tools can understand and generate consistently.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (363, 10, 3, 'Figma-to-Code with MCP & Code Connect', 'Connect your design system in Figma directly to your codebase using Model Context Protocol (MCP) and Code Connect. Learn to structure Figma files so AI agents produce design-informed code generation.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (364, 10, 4, 'Production Component Architecture with shadcn/ui', 'Build production-grade UI with shadcn/ui and Tailwind CSS. Learn why AI coding tools love shadcn/ui transparent architecture and how to customize components while maintaining design system consistency.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2341, 38, 1, 'Understanding Growth Mindset: Core Foundations', 'Explore the fundamental differences between fixed and growth mindsets, understanding how our belief systems shape learning and personal development. Learn the psychological principles behind mindset and how it impacts motivation and resilience.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2342, 38, 2, 'Cognitive Strategies for Cultivating Growth Mindset', 'Develop practical mental techniques to reframe challenges, embrace failures as learning opportunities, and build self-awareness. Focus on internal dialogue, positive self-talk, and strategies to overcome self-limiting beliefs.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2343, 38, 3, 'Applying Growth Mindset in Personal and Professional Contexts', 'Translate growth mindset principles into actionable behaviors across different life domains, including academic learning, career development, and interpersonal relationships. Learn how to set adaptive goals and approach challenges constructively.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (2344, 38, 4, 'Sustaining and Advancing Your Growth Mindset Journey', 'Integrate learned strategies into a comprehensive personal development framework, creating sustainable habits that support continuous learning and self-improvement. Develop a personalized growth plan and reflective practices.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (263, 12, 1, 'Constitutional Foundations', 'Explore the origins and principles of the US Constitution. Understand the framers intent and the structure of government and the foundational concepts of federalism and separation of powers and checks and balances.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (264, 12, 2, 'The Three Branches of Government', 'Deep dive into the legislative and executive and judicial branches. Understand how laws are made and enforced and interpreted and how the branches interact with each other.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (265, 12, 3, 'Rights Liberties and Citizenship', 'Examine the Bill of Rights and subsequent amendments. Understand civil liberties and civil rights and what it means to be a citizen in a democratic society.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (266, 12, 4, 'Civic Action: Creating Change in Your Community', 'Learn how ordinary citizens can influence policy and create social change. From voting to organizing to advocacy discover practical ways to participate in democracy.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1254, 30, 1, 'Introduction to AI Evaluation Fundamentals', 'Learn the core principles of AI evaluation and why systematic testing is crucial for AI-generated code. Understand the basic metrics and conceptual frameworks for assessing AI performance.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1255, 30, 2, 'Metrics and Measurement Techniques', 'Dive deep into quantitative and qualitative metrics for evaluating AI code generation. Explore accuracy, relevance, efficiency, and contextual appropriateness measurement methods.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1256, 30, 3, 'Error Detection and Bias Analysis', 'Identify and analyze potential errors, biases, and inconsistencies in AI-generated code. Learn techniques to systematically uncover hidden flaws and systematic mistakes.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1257, 30, 4, 'Practical Testing Frameworks', 'Implement hands-on testing strategies using popular frameworks and tools for AI code evaluation. Create structured test suites and develop repeatable evaluation processes.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1258, 30, 5, 'Performance and Efficiency Evaluation', 'Assess the computational performance, memory usage, and scalability of AI-generated code. Learn benchmarking techniques and optimization strategies for AI code outputs.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1259, 30, 6, 'Safety and Security Assessments', 'Deep dive into evaluating AI-generated code for potential security vulnerabilities, ethical concerns, and compliance with best practices. Develop robust safety evaluation methodologies.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1260, 30, 7, 'Advanced Evaluation Techniques', 'Explore sophisticated evaluation methods including machine learning-based assessment, automated testing strategies, and cutting-edge diagnostic approaches for AI code generation.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1261, 30, 8, 'Comprehensive AI Evaluation Strategy Design', 'Synthesize all learned techniques to design a holistic, adaptive evaluation strategy. Create a custom framework for continuous improvement and rigorous AI code assessment.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1686, 15, 1, 'Learning to Code in the AI Age', 'Understand how to approach programming in the AI era. Learn HTML basics and set up your development environment while building good learning habits.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1687, 15, 2, 'CSS for Visual Delight', 'Master CSS styling and animations to create visually engaging web experiences. Learn transitions and keyframes and modern layout techniques.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (198, 37, 1, 'Foundations of Effective Learning', 'Explore the core principles of learning, understanding how your brain processes and retains information. Discover your personal learning style and develop a growth mindset that enables continuous skill acquisition.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (199, 37, 2, 'Cognitive Strategies and Memory Techniques', 'Learn advanced memory techniques, including spaced repetition, active recall, and mental mapping. Master strategies to improve comprehension, retention, and quick information processing across different domains.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (200, 37, 3, 'Skill Deconstruction and Accelerated Learning', 'Develop a systematic approach to breaking down complex skills into manageable components. Learn how to create efficient learning plans, identify critical learning paths, and rapidly acquire new abilities using proven methodologies.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (201, 37, 4, 'Metacognition and Lifelong Learning Mastery', 'Integrate all previous learning strategies into a comprehensive personal learning system. Explore self-reflection techniques, develop adaptive learning skills, and create a sustainable framework for continuous personal and professional growth.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1688, 15, 3, 'JavaScript Fundamentals', 'Learn core JavaScript concepts including variables and functions and DOM manipulation. Build interactive features for your web pages.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1689, 15, 4, 'Frontend Frameworks Survey', 'Survey the modern frontend framework landscape. Compare React and Vue and Svelte to understand when and why to use each one.') ON CONFLICT DO NOTHING;
