INSERT INTO weeks (id, binder_id, index, title, description) VALUES (223, 39, 1, 'Posthog Analytics Fundamentals: Setup and Core Features', 'Learn how to set up Posthog, configure basic tracking, and understand its key analytics capabilities. This week covers installation, event tracking, user insights, and navigating the Posthog dashboard to gain initial product intelligence.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1274, 44, 1, 'Bootstrapping Fundamentals & Economic Principles', 'Explore the core economic principles that govern lean startup formation without initial capital, including revenue-first thinking and sustainable unit economics. Learn how successful bootstrapped founders validate market demand and establish initial product-market fit on minimal resources.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (258, 40, 1, 'Foundations of Fish Preparation and Cooking Techniques', 'Learn essential fish handling, safety, selection, and basic cooking methods. Explore different types of fish, how to identify freshness, proper cutting techniques, and fundamental cooking approaches like baking, pan-frying, and grilling.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1275, 44, 2, 'Revenue Models & Sustainable Profitability', 'Master the mechanics of building sustainable business models where profit margins directly determine survival and growth. Analyze how bootstrapped startups design pricing strategies, manage cash flow, and achieve operational profitability from day one.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1276, 44, 3, 'Scaling Operations & Team Expansion Strategy', 'Determine the optimal timing and approach for hiring your first employees while maintaining unit economics and bootstrapped constraints. Learn frameworks for delegating effectively, identifying which roles to hire first, and growing without external capital.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1277, 44, 4, 'Risk Management & Decision-Making for Early-Stage Ventures', 'Navigate common pitfalls that undermine bootstrapped startups and develop decision-making frameworks for managing risk-return tradeoffs. Apply strategic thinking to avoid failure modes and make informed choices about when to pivot, persevere, or scale.') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1338, 23, 1, 'Foundations', 'Understanding Claude API fundamentals and introduction to agentic AI concepts') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1339, 23, 2, 'Web Architecture & Agentic Patterns', 'Building web applications with Claude integration and understanding agentic system architectures') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1340, 23, 3, 'Production Optimization & Scaling', 'Advanced optimization techniques, production deployment strategies, and scaling agentic systems with cost efficiency') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (1341, 23, 4, 'Enterprise Applications & Business Impact', 'Real-world enterprise deployments, business case studies, and strategies for scaling agentic systems for organizational transformation') ON CONFLICT DO NOTHING;
