INSERT INTO weeks (id, binder_id, index, title, description) VALUES (259, 27, 1, 'Foundations', 'Introduction to the major schools and historical context of Chinese classical philosophy') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (260, 27, 2, 'Human Nature Debate', 'The famous debate between Mencius and Xunzi on whether human nature is fundamentally good or evil') ON CONFLICT DO NOTHING;
INSERT INTO weeks (id, binder_id, index, title, description) VALUES (261, 27, 3, 'Philosophy vs Politics', 'The tension between Zhuangzi''s radical skepticism and wu wei versus the Legalists'' pragmatic authoritarianism') ON CONFLICT DO NOTHING;
