INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4546, 1254, 1, 'reading', 'Curious Beginner''s Guide to AI Evaluations', 'https://creatoreconomy.so/p/curious-beginners-guide-to-ai-evaluations', '<p>Start with this practical, step-by-step walkthrough that demonstrates how to build AI evaluations from scratch using a real customer support example. Perfect for beginners who want to understand the fundamentals through hands-on learning.</p>', 'Peter Yang', '2025-08-20', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4547, 1254, 2, 'reading', 'Demystifying Evals for AI Agents', 'https://www.anthropic.com/engineering/demystifying-evals-for-ai-agents', '<p>Learn core evaluation concepts from industry practitioners. This reading explains why systematic testing matters, introduces key terminology like graders and success criteria, and shows how evaluation prevents reactive development cycles.</p>', 'Anthropic Engineering', '2025-01-15', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4548, 1254, 3, 'reading', 'A Survey on Evaluation of Large Language Models', 'https://arxiv.org/abs/2307.03109', '<p>Academic overview covering three evaluation dimensions: what to evaluate, where to evaluate, and how to evaluate. Skim sections 1-3 for conceptual frameworks that underpin modern AI evaluation approaches.</p>', 'Yupeng Chang et al.', '2023-12-29', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4549, 1254, 4, 'exercise', 'Build Your First Eval: AI-Generated Feature Test', NULL, NULL, NULL, NULL, NULL, '<p>**Your task:** Think of a simple feature you''ve built or used that incorporates AI-generated code (e.g., a chatbot response, an auto-complete suggestion, a simple script).</p><ol><li><p>Write down **3 test scenarios** for this feature (1 common case, 1 edge case, 1 failure case)</p></li><li><p>For each scenario, define what "good" output looks like in 1-2 sentences</p></li><li><p>Create a simple checklist with 3 criteria to evaluate whether the AI-generated code works correctly</p></li><li><p>Test the feature manually against your criteria and document what passed/failed</p></li></ol><p>Submit: A simple markdown document with your scenarios, criteria, and test results. Focus on clarity over complexity.</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4550, 1255, 1, 'reading', 'Measuring the Performance of AI Code Generation: A Practical Guide', 'https://www.walturn.com/insights/measuring-the-performance-of-ai-code-generation-a-practical-guide', '<p>Explore key metrics for code evaluation: functional accuracy (pass@k), similarity metrics (BLEU, CodeBLEU), and practical approaches to measuring whether AI-generated code actually works.</p>', 'Walturn', '2024-06-25', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4551, 1255, 2, 'reading', 'Benchmarks and Metrics for Evaluations of Code Generation: A Critical Review', 'https://arxiv.org/html/2406.12655v1', '<p>Academic paper reviewing evaluation benchmarks (HumanEval, MBPP) and metrics for code generation. Focus on sections discussing usability metrics like readability, maintainability, and accuracy to understand multi-dimensional quality assessment.</p>', 'Multiple Authors', '2024-06-18', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4552, 1255, 3, 'reading', 'Human-Centered AI Evaluation: Contextual Appropriateness', 'https://galileo.ai/blog/human-evaluation-metrics-ai', '<p>Learn how to assess qualitative dimensions like relevance, fluency, and contextual appropriateness that automated metrics often miss. Understand when human judgment is essential for evaluating AI outputs.</p>', 'Galileo AI', '2025-03-09', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4553, 1255, 4, 'exercise', 'Multi-Metric Code Quality Assessment', NULL, NULL, NULL, NULL, NULL, '<p>**Your task:** Pick one AI-generated code snippet (your own, from GitHub Copilot, ChatGPT, etc. — min. 10 lines).</p><p>**Evaluate it across 4 dimensions:**</p><ol><li><p>**Functional Accuracy:** Does it produce correct output? Test with 3 inputs and document pass/fail.</p></li><li><p>**Efficiency:** Is the approach optimal? Identify any performance issues (time/space).</p></li><li><p>**Readability:** Can a peer understand it easily? Rate 1-5 with specific examples.</p></li><li><p>**Contextual Fit:** Does it match your project''s style, constraints, and use case? Explain in 2-3 sentences.</p></li></ol><p>**Deliverable:** Create a simple evaluation scorecard (spreadsheet or markdown table) showing your ratings and notes for each dimension. Reflect: Which metric matters most for your use case?</p>', 75) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4554, 1256, 1, 'reading', 'A Survey of Bugs in AI-Generated Code', 'https://arxiv.org/html/2512.05239v1', '<p>Read sections 1-3 to understand common bug patterns (misunderstandings, hallucinations, omitted edge cases) in AI-generated code and why they''re harder to diagnose than typical bugs.</p>', 'ArXiv Authors', '2024-12-04', 'Journal Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4555, 1256, 2, 'reading', 'Detecting Errors in AI-Generated Code', 'https://stackoverflow.blog/2024/09/20/detecting-errors-in-ai-generated-code/', '<p>An accessible introduction to error detection in LLM-generated code, covering hallucinations and the need for systematic testing tools.</p>', 'Stack Overflow', '2024-09-20', 'Blog/Article', NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4556, 1256, 3, 'reading', 'AI Model Bias: How to Detect and Mitigate', 'https://testrigor.com/blog/ai-model-bias/', '<p>Learn practical techniques for detecting bias in AI systems, including filtering bias, optimization bias, and tools like SHAP and LIME for feature importance analysis.</p>', 'testRigor', '2025-05-02', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4557, 1256, 4, 'exercise', 'Create an Error Detection Checklist', NULL, NULL, NULL, NULL, NULL, '<p>Build your own error detection checklist for AI-generated code:</p><ol><li><p>Pick a small AI-generated function (or generate one with ChatGPT/Copilot)</p></li><li><p>Create a checklist with 3 categories:</p><ul><li><p>**Logic errors** (edge cases, assumptions, hallucinations)</p></li><li><p>**Bias indicators** (does it favor certain inputs or patterns?)</p></li><li><p>**Security issues** (hardcoded values, unsafe operations)</p></li></ul></li><li><p>Test your function against the checklist and document 2-3 issues you find</p></li></ol><p>Write a short reflection (200 words): What surprised you? What patterns emerged?</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4558, 1257, 1, 'reading', 'A Beginner''s Guide to Unit Testing with Pytest', 'https://betterstack.com/community/guides/testing/pytest-guide/', '<p>Hands-on guide covering pytest basics: installation, writing your first tests, fixtures, and parametrization. Follow along with the code examples to build your testing skills.</p>', 'Better Stack', '2024-01-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4559, 1257, 2, 'reading', 'Getting Started With Testing in Python', 'https://realpython.com/python-testing/', '<p>Understand the fundamentals of testing in Python, including unittest and pytest frameworks, test runners, and when to use different testing approaches.</p>', 'Real Python', '2024-08-16', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4560, 1257, 3, 'reading', 'What is an LLM Evaluation Framework?', 'https://www.evidentlyai.com/blog/llm-evaluation-framework', '<p>Learn how to design evaluation frameworks for AI systems, including test datasets, evaluators, and metrics. Focus on sections about creating structured test suites.</p>', 'Evidently AI', '2024-01-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4561, 1257, 4, 'exercise', 'Build Your First AI Code Test Suite', NULL, NULL, NULL, NULL, NULL, '<p>Create a simple test suite for an AI-generated function:</p><ol><li><p>Generate a function using ChatGPT (e.g., a text parser or calculator)</p></li><li><p>Install pytest: `pip install pytest`</p></li><li><p>Write 5 test cases:</p><ul><li><p>2 tests for expected inputs (happy path)</p></li><li><p>2 tests for edge cases (empty input, null, extreme values)</p></li><li><p>1 test for an error condition</p></li></ul></li><li><p>Run your tests: `pytest`</p></li><li><p>Fix any failures and document what you learned</p></li></ol><p>Bonus: Add one parametrized test that runs multiple inputs through the same test logic.</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4562, 1258, 1, 'reading', 'EffiBench: Benchmarking the Efficiency of Automatically Generated Code', 'https://arxiv.org/abs/2402.02037', '<p>Academic paper introducing a benchmark for evaluating execution time and memory usage of AI-generated code. Focus on how they measure efficiency metrics like execution time and memory consumption.</p>', 'Huang Dong et al.', '2024-02-03', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4563, 1258, 2, 'reading', 'Introduction to Memory Profiling in Python', 'https://www.datacamp.com/tutorial/memory-profiling-python', '<p>Practical tutorial on using memory profiling tools like memory_profiler and tracemalloc to analyze and optimize memory usage in Python applications.</p>', 'Oluseye Jeremiah', '2024-06-21', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4564, 1258, 3, 'reading', 'Scalability Testing: A Complete Guide', 'https://testlio.com/blog/what-is-scalability-testing/', '<p>Comprehensive guide covering how to test if code can handle increased loads. Learn about key metrics like response time, CPU usage, and memory consumption under varying demands.</p>', 'Testlio', '2024-11-22', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4565, 1258, 4, 'exercise', 'Profile and Optimize Your AI-Generated Code', NULL, NULL, NULL, NULL, NULL, '<p>Choose a piece of code generated by AI (from a previous project or create one now with a prompt like ''write a function to process a large dataset'').</p><ol><li><p>Profile its performance: Measure execution time and memory usage using basic tools (Python''s time module or browser DevTools)</p></li><li><p>Identify bottlenecks: Find the slowest or most memory-intensive parts</p></li><li><p>Create a simple test: Run it with different input sizes (small, medium, large)</p></li><li><p>Document your findings: What performance issues did you discover? Would this code scale?</p></li></ol><p>Share your results in a brief report (1-2 paragraphs) describing the performance characteristics you measured.</p>', 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4566, 1259, 1, 'reading', 'Cybersecurity Risks of AI-Generated Code', 'https://cset.georgetown.edu/publication/cybersecurity-risks-of-ai-generated-code/', '<p>Research paper analyzing three categories of risks in AI code generation: generating insecure code, model vulnerabilities, and downstream impacts. Understand the security landscape of AI-generated code.</p>', 'Jessica Ji, Jenny Jun, Maggie Wu, Rebecca Gelles', '2024-11-19', 'Journal Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (50, 15, 7, 'exercise', 'Map Your AI Knowledge', NULL, 'Create a visual timeline of AI development from 2017 to present.', NULL, NULL, NULL, 'Include key model releases with parameter counts and major capability breakthroughs and a 200-word reflection.', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (57, 16, 7, 'exercise', 'AI Tool Evaluation', NULL, 'Try at least 2 AI coding or writing tools for a small task.', NULL, NULL, NULL, 'Create a comparison matrix covering ease of use and quality of output and speed and cost. Write a recommendation.', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (44, 15, 1, 'reading', 'Large Language Model - Wikipedia', 'https://en.wikipedia.org/wiki/Large_language_model', 'Comprehensive overview of LLMs including architecture and training and evolution.', 'Wikipedia', '2025-01-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (45, 15, 2, 'reading', 'But What Is a GPT? Visual Intro to Transformers (YouTube)', 'https://www.youtube.com/watch?v=wjZofJX0v4M', '3Blue1Brown visual explanation of transformer architecture and word embeddings. Makes complex concepts intuitive through beautiful animations.', '3Blue1Brown (Grant Sanderson)', '2024-01-01', 'YouTube Video', NULL, 27) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (46, 15, 3, 'reading', 'A Brief History of LLMs: From Transformers to DeepSeek-R1', 'https://medium.com/@lmpo/a-brief-history-of-lmms-from-transformers-2017-to-deepseek-r1-2025-dae75dd3f59a', 'Traces the evolution from 2017 Transformer architecture through GPT and BERT and ChatGPT.', 'LM Po', '2025-11-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (47, 15, 4, 'reading', 'Generative Pre-trained Transformer - Wikipedia', 'https://en.wikipedia.org/wiki/Generative_pre-trained_transformer', 'Deep dive into GPT architecture from GPT-1 through GPT-4o and reasoning models.', 'Wikipedia', '2025-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (48, 15, 5, 'reading', 'Large Language Models 101: History Evolution and Future', 'https://www.scribbledata.io/blog/large-language-models-history-evolutions-and-future/', 'Covers the evolution from LSTM networks to transformers and sparse expert models.', 'Scribble Data', '2025-09-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (49, 15, 6, 'reading', 'The History of Large Language Models', 'https://www.whaleflux.com/blog/the-history-of-large-language-models/', 'Comprehensive history from Dartmouth Conference to Claude 3 and DeepSeek R1.', 'WhaleFlux', '2025-08-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (51, 16, 1, 'reading', 'Top 10 Vibe Coding Tools in 2026', 'https://www.nucamp.co/blog/top-10-vibe-coding-tools-in-2026-cursor-copilot-claude-code-more', 'Comprehensive comparison of AI coding assistants including Cursor and Copilot and Windsurf and Claude Code.', 'Nucamp', '2026-01-01', 'Blog/Article', NULL, 35) ON CONFLICT DO NOTHING;
