INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (53, 16, 3, 'reading', 'GitHub Copilot vs Cursor: AI Code Editor Review', 'https://www.digitalocean.com/resources/articles/github-copilot-vs-cursor', 'Detailed comparison of the two leading AI coding assistants with real-world use cases.', 'DigitalOcean', '2025-01-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (54, 16, 4, 'reading', 'Programming with AI: Workflows for Claude and Copilot and Cursor', 'https://graphite.com/guides/programming-with-ai-workflows-claude-copilot-cursor', 'Practical workflow guide for integrating different AI assistants into development practice.', 'Graphite', '2025-01-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (56, 16, 6, 'reading', 'Cursor vs Copilot: Which AI Coding Tool is Best?', 'https://zapier.com/blog/cursor-vs-copilot/', 'Practical comparison focused on helping beginners choose the right tool.', 'Zapier', '2025-06-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (58, 17, 1, 'reading', 'AI Code Guide: A Roadmap to Start Coding with AI', 'https://github.com/automata/aicodeguide', 'Comprehensive guide covering the spectrum from AI as copilot to vibe coding with best practices.', 'automata', '2025-01-01', 'Blog/Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (59, 17, 2, 'reading', 'LLM Course: Chapter on Prompt Engineering', 'https://github.com/mlabonne/llm-course', 'Comprehensive open-source LLM course covering prompt engineering and fine-tuning and deployment. The prompt engineering section is essential for product builders.', 'Maxime Labonne', '2024-01-01', 'Book Chapter', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (60, 17, 3, 'reading', 'Beyond Vibe Coding: AI-Assisted Coding With Cursor and Opik', 'https://www.comet.com/site/blog/cursor-vibe-coding/', 'Explains the difference between vibe coding and AI-assisted coding with practical guidance.', 'Comet', '2025-09-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4567, 1259, 2, 'reading', 'OWASP Secure Code Review Cheat Sheet', 'https://cheatsheetseries.owasp.org/cheatsheets/Secure_Code_Review_Cheat_Sheet.html', '<p>Practical guide to manual security code review. Learn to check for common vulnerabilities like SQL injection, XSS, and authentication flaws using OWASP''s checklist approach.</p>', 'OWASP Foundation', '2024-01-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (63, 17, 6, 'exercise', 'Build with AI Assistance', NULL, 'Build a simple tool or webpage using AI assistance.', NULL, NULL, NULL, 'Document your prompts and what AI got right/wrong and how you iterated. Share your project and lessons learned.', 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (69, 18, 6, 'exercise', 'AI Product Concept', NULL, 'Develop a concept for an AI-enhanced product.', NULL, NULL, NULL, 'Include problem being solved and how AI capabilities address it and ethical considerations and potential limitations. Present as a 1-page product brief.', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4568, 1259, 3, 'reading', 'The Scales of Justitia: A Comprehensive Survey on Safety Evaluation of LLMs', 'https://arxiv.org/html/2506.11094v2', '<p>Survey examining ethical concerns and safety evaluation of LLMs, including code generation safety, toxicity, bias, and privacy risks. Understand broader ethical dimensions beyond technical security.</p>', 'arXiv', '2025-10-30', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4569, 1259, 4, 'exercise', 'Security Audit Your AI-Generated Code', NULL, NULL, NULL, NULL, NULL, '<p>Take a piece of AI-generated code (your own or generate something like ''create a login form'' or ''build a data API endpoint'').</p><ol><li><p>Manual security review: Check for 3-5 OWASP risks (e.g., hardcoded secrets, missing input validation, SQL injection risk, weak authentication)</p></li><li><p>Test one vulnerability: Can you demonstrate the security flaw? (Example: inject invalid input, access without auth)</p></li><li><p>Rate the risk: Assign severity (low/medium/high) based on potential impact</p></li><li><p>Propose fixes: How would you secure this code?</p></li></ol><p>Write up your findings as a simple security report documenting what you found and how to fix it.</p>', 75) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4570, 1260, 1, 'reading', 'Testing Machine Learning Systems: Code, Data and Models', 'https://madewithml.com/courses/mlops/testing/', '<p>Learn how to test code, data, and ML models systematically including behavioral testing and coverage strategies for AI systems.</p>', 'Anyscale', '2023-01-15', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4571, 1260, 2, 'reading', 'Benchmarks and Metrics for Evaluations of Code Generation: A Critical Review', 'https://arxiv.org/html/2406.12655v1', '<p>Academic review examining state-of-the-art benchmarks, metrics, and evaluation approaches for AI code generation including pass@k and quality attributes.</p>', 'arXiv', '2024-06-18', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4572, 1260, 3, 'reading', 'Machine Learning Algorithms for Test Automation', 'https://labs.sogeti.com/machine-learning-algorithms-for-test-automation/', '<p>Explore how decision trees, neural networks, and reinforcement learning are applied to defect prediction, test case optimization, and self-healing automation.</p>', 'Sogeti Labs', '2025-02-26', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4573, 1260, 4, 'exercise', 'Design Advanced Diagnostic Tests', NULL, NULL, NULL, NULL, NULL, '<p>Build an advanced evaluation suite for your AI-generated feature:</p><ul><li><p>Create 5 behavioral tests that check edge cases and unexpected inputs</p></li><li><p>Design 3 automated quality checks (code complexity, security patterns, performance)</p></li><li><p>Implement one machine-learning inspired test that adapts based on previous failures</p></li><li><p>Document how each test reveals different aspects of code quality</p></li></ul><p>Focus on tests that go beyond simple pass/fail to reveal deeper insights about AI code behavior.</p>', 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4574, 1261, 1, 'reading', 'Holistic Evaluation of Language Models (HELM)', 'https://arxiv.org/abs/2211.09110', '<p>Explore Stanford''s comprehensive framework for evaluating AI models across multiple scenarios and metrics including accuracy, fairness, robustness, and efficiency.</p>', 'Percy Liang et al.', '2023-10-01', 'Journal Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4575, 1261, 2, 'reading', 'AI Agent Evaluation: Frameworks, Strategies, and Best Practices', 'https://medium.com/online-inference/ai-agent-evaluation-frameworks-strategies-and-best-practices-9dc3cfdf9890', '<p>Learn how to build comprehensive evaluation strategies considering technical capabilities, autonomy levels, and business objectives for AI systems.</p>', 'Dave Davies', '2024-12-02', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4576, 1261, 3, 'reading', 'Transforming Language into Code: Building and Evaluating a Robotic Code Generation Copilot', 'https://devblogs.microsoft.com/ise/code-generation-evaluation/', '<p>Discover practical insights on evaluation metrics, data sources, and expert feedback strategies for optimizing AI code generation in real-world scenarios.</p>', 'Microsoft ISE', '2024-12-16', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4577, 1261, 4, 'exercise', 'Design Your Custom AI Evaluation Framework', NULL, NULL, NULL, NULL, NULL, '<p>Create a comprehensive, adaptive evaluation strategy for your AI-coded feature:</p><ol><li><p>Define 3-5 evaluation goals aligned with your project needs (correctness, maintainability, security, etc.)</p></li><li><p>Select appropriate metrics for each goal (both automated and human-assessed)</p></li><li><p>Design a continuous monitoring process with feedback loops</p></li><li><p>Create an improvement roadmap showing how evaluation results drive iterations</p></li><li><p>Document decision criteria for when code passes vs. needs revision</p></li></ol><p>Your framework should be practical, sustainable, and adaptable to changing requirements.</p>', 95) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (62, 17, 5, 'reading', 'Cursor vs Copilot: Choosing the Best AI Coding Assistant', 'https://blog.promptlayer.com/cursor-vs-copilot-choosing-the-best-ai-coding-assistant/', 'Deep comparison covering model flexibility and context handling and real-world performance metrics.', 'PromptLayer', '2025-09-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (64, 18, 1, 'reading', 'Large Language Models: Their History Capabilities and Limitations', 'https://snorkel.ai/large-language-models/', 'Comprehensive technical overview including embeddings and transformers and limitations like hallucination and bias.', 'Snorkel AI', '2025-01-01', 'Blog/Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (65, 18, 2, 'reading', 'ChatGPT Prompt Engineering for Developers (YouTube)', 'https://www.youtube.com/watch?v=H4YK_7MAckk', 'DeepLearning.AI short course on prompt engineering best practices. Covers guidelines and iterative development and summarizing and inferring.', 'DeepLearning.AI (Andrew Ng and Isa Fulford)', '2023-01-01', 'YouTube Video', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (66, 18, 3, 'reading', 'AI Evolution: What is a Large Language Model?', 'https://www.stjohns.edu/news-media/johnnies-blog/ai-evolution-what-large-language-model', 'Accessible explanation of LLMs including how attention mechanisms work and current challenges.', 'St. Johns University', '2025-01-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (67, 18, 4, 'reading', 'The Evolution of LLM: From Early AI to Open-Source Innovation', 'https://www.loata.ai/blogs/123e4567-e89b-12d3-a456-426614174000', 'Covers the rise of open-source models like LLaMA and GPT-Neo and the future of real-time learning.', 'Loata AI', '2025-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (68, 18, 5, 'reading', 'LLM Part-1: History of Language Modeling', 'https://medium.com/@utkarsh.mathur/llm-part-1-history-of-language-modeling-5f2f17e1a8b4', 'Technical deep dive into the evolution from statistical language models to modern LLMs with emergent abilities.', 'Utkarsh Mathur', '2025-05-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (104, 23, 7, 'exercise', 'Typography Hierarchy Project', NULL, 'Design a single-page flyer for an event using only typography.', NULL, NULL, NULL, 'Create clear hierarchy with headline and subheading and body text and details. Use no more than 2 typefaces. Submit with annotations.', 60) ON CONFLICT DO NOTHING;
