INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (113, 25, 2, 'reading', 'Universal Principles of Design: Layout and Composition', 'https://www.amazon.com/Universal-Principles-Design-Revised-Updated/dp/1592535879', 'Classic design reference book. Focus on the grid systems and visual hierarchy and alignment principles sections for layout mastery.', 'William Lidwell and Kritina Holden and Jill Butler', '2010-01-01', 'Book Chapter', NULL, 45) ON CONFLICT DO NOTHING;
