INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (117, 25, 6, 'reading', 'Color Theory for Beginners: Step-by-Step Guide', 'https://618media.com/en/blog/color-theory-for-beginners/', 'Primary and secondary and tertiary colors plus color harmony and psychology in layout.', '618 Media', '2024-03-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (119, 26, 1, 'reading', 'A Guide to Color Theory in Graphic Design', 'https://www.park.edu/blog/a-guide-to-color-theory-in-graphic-design/', 'How color theory applies to graphic design with examples of color harmonies in practice.', 'Park University', '2025-05-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (120, 26, 2, 'reading', '4 Principles of Visual Design (YouTube)', 'https://www.youtube.com/watch?v=ZK86XQ1iFVs', 'Design fundamentals covering proximity and alignment and repetition and contrast (PARC). Demonstrates how these principles work together.', 'The Futur', '2020-01-01', 'YouTube Video', NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (121, 26, 3, 'reading', 'Color Theory: Brief Guide for Designers', 'https://blog.tubikstudio.com/color-theory-brief-guide-for-designers/', 'Color wheel and RGB/CMYK and models of color harmony in UI design context.', 'Tubik Studio', '2017-03-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (122, 26, 4, 'reading', 'The Complete Guide to Color Theory and Its Application', 'https://digitalarcane.com/complete-guide-to-color-theory-beginners-2024/', 'Comprehensive 2024 guide covering branding and interior design and digital applications.', 'Digital Arcane', '2024-01-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (123, 26, 5, 'reading', 'Learn Typography Fundamentals', 'https://www.thefutur.com/content/learn-typography', 'The Futurs professional typography course overview covering the four-part design fundamentals approach.', 'The Futur', '2024-01-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (124, 26, 6, 'reading', 'Colour Theory for Graphic Designers', 'https://adgenix.io/learning/colour-theory-for-graphic-designers/', 'Science and art of color theory with focus on CMYK for print and RGB for digital.', 'Adgenix', '2024-01-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5551, 2341, 1, 'reading', 'Fixed vs. Growth: The Two Basic Mindsets That Shape Our Lives', 'https://www.themarginalian.org/2014/01/29/carol-dweck-mindset/', '<p>This accessible overview introduces Dweck''s fundamental distinction between fixed and growth mindsets, exploring how our beliefs about intelligence shape our relationship with success, failure, and learning.</p>', 'Maria Popova (discussing Carol Dweck)', '2021-08-31', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5552, 2341, 2, 'reading', 'Mindsets: A View From Two Eras', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC6594552/', '<p>An academic article by mindset researcher Carol Dweck herself, tracing the evolution of mindset research and explaining the psychological principles behind how beliefs influence motivation, resilience, and achievement.</p>', 'Carol S. Dweck and David S. Yeager', '2019-05-01', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5553, 2341, 3, 'reading', 'Neuroplasticity: How the Brain Changes with Learning', 'https://solportal.ibeunesco.org/articles/neuroplasticity-how-the-brain-changes-with-learning/', '<p>Learn the biological foundation of growth mindset: how your brain physically changes when you learn, and why this means your abilities truly can develop over time.</p>', 'International Bureau of Education (UNESCO)', '2021-06-28', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (823, 195, 1, 'reading', 'Business Model Canvas Explained', 'https://www.alexandercowan.com/business-model-canvas-templates/', '<p>This practical guide introduces the Business Model Canvas, a one-page tool that helps visualize and design business models. Focus on understanding the 9 building blocks and how they interconnect to create value.</p>', 'Alexander Cowan', '2022-10-28', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (824, 195, 2, 'reading', 'How to Build a Compelling Value Proposition', 'https://underscore.vc/resources/how-to-write-a-value-proposition/', '<p>Learn the 4Us framework for crafting strong value propositions: Unworkable, Unavoidable, Urgent, and Underserved problems. This resource emphasizes creating 10x improvements over the status quo for tech startups.</p>', 'Underscore VC', '2024-03-24', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (825, 195, 3, 'reading', 'Business Model Innovation: A Review of the Process-Based Literature', 'https://link.springer.com/article/10.1007/s10997-021-09590-w', '<p>Academic review examining how business models can be changed and innovated. Focus on understanding the cognitive and strategic processes entrepreneurs use when developing new business models for tech ventures.</p>', 'Journal of Management and Governance', '2021-08-14', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (826, 195, 4, 'exercise', 'Design Your Business Model Canvas', NULL, NULL, NULL, NULL, NULL, '<p>Create a complete Business Model Canvas for your tech startup idea (real or hypothetical):</p><ol><li><p>Identify your customer segments and value propositions</p></li><li><p>Map out channels, customer relationships, and revenue streams</p></li><li><p>Define key activities, resources, and partnerships</p></li><li><p>Outline your cost structure</p></li></ol><p>Present your canvas visually (paper, digital tool, or slides). Write a 2-paragraph reflection explaining:</p><ul><li><p>Which element was most challenging to define and why?</p></li><li><p>What insights did you gain about your business model''s viability?</p></li></ul>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (847, 201, 1, 'reading', 'Why Reflect? Effective Learning through Metacognition and Self-Regulation', 'https://learning.nd.edu/news/why-reflect-effective-learning-through-metacognition-and-self-regulation/', '<p>Discover how structured reflection and metacognition increase learning effectiveness. Learn practical strategies for self-evaluation that help you understand what works, what doesn''t, and why—essential for continuous improvement.</p>', 'University of Notre Dame Learning', '2024-11-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (848, 201, 2, 'reading', 'Lifelong Learning: Meaning, Importance, Benefits & Examples', 'https://www.valamis.com/hub/lifelong-learning', '<p>Explore the comprehensive framework of lifelong learning as self-initiated education focused on personal development. Understand how to build sustainable learning habits that extend beyond formal education.</p>', 'Valamis', '2025-11-25', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (849, 201, 3, 'reading', 'Approaching Lifelong Learning: An Integrated Framework', 'https://www.sciencedirect.com/science/article/abs/pii/S2211949324000115', '<p>Read this academic article conceptualizing lifelong learning as an ongoing, self-directed search for knowledge. It presents an integrated framework for understanding decision-making in personal and professional development.</p>', 'Cañas et al.', '2024-05-04', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5554, 2341, 4, 'exercise', 'Your Mindset Map', NULL, NULL, NULL, NULL, NULL, '<p>**Create a personal mindset inventory:**</p><ol><li><p>List 3-5 areas of your life (e.g., career, relationships, hobbies, learning new skills)</p></li><li><p>For each area, write down:</p><ul><li><p>A recent challenge or setback you faced</p></li><li><p>Your immediate thoughts about why it happened</p></li><li><p>Whether those thoughts reflect fixed or growth mindset patterns</p></li></ul></li><li><p>Choose ONE area where you notice fixed mindset thinking</p></li><li><p>Rewrite your story from a growth mindset perspective: What could you learn? What strategies could you try? How might effort and practice change the outcome?</p></li></ol><p>**Reflect:** Which mindset feels more natural to you right now? Where did these beliefs come from?</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5555, 2342, 1, 'reading', 'Positive Reframing and Examining the Evidence', 'https://sdlab.fas.harvard.edu/cognitive-reappraisal/positive-reframing-and-examining-evidence', '<p>Learn two powerful cognitive strategies for reappraising challenges: finding benefits in difficult situations and examining evidence to test your assumptions about setbacks.</p>', 'Harvard Stress & Development Lab', '2020-01-15', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5556, 2342, 2, 'reading', 'How to Learn From Your Failures', 'https://greatergood.berkeley.edu/article/item/how_to_learn_from_your_failures', '<p>Discover why most people struggle to learn from failure and practical techniques to overcome emotional barriers, reframe setbacks, and grow from mistakes.</p>', 'Jeremy Adam Smith', '2022-08-24', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5557, 2342, 3, 'reading', 'The Beginner''s Guide to Self-Compassion', 'https://nickwignall.com/self-compassion-guide/', '<p>An accessible introduction to self-compassion and its role in building self-awareness and silencing your inner critic. Learn how being kind to yourself actually fuels motivation and growth.</p>', 'Nick Wignall', '2022-01-10', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5558, 2342, 4, 'exercise', 'Reframe Your Inner Dialogue', NULL, NULL, NULL, NULL, NULL, '<p>**Transform your self-talk from critic to coach:**</p><ol><li><p>**Catch Your Critic** (15 min): For one day, notice when your inner voice is harsh. Write down 3-5 self-critical thoughts you had (exact words matter!).</p></li><li><p>**Investigate** (15 min): For each thought, ask:</p><ul><li><p>Is this actually true, or am I exaggerating?</p></li><li><p>Would I say this to a friend in the same situation?</p></li><li><p>What evidence contradicts this thought?</p></li></ul></li><li><p>**Reframe** (20 min): Rewrite each critical thought with compassion and growth mindset language. Focus on what you can learn, try differently, or how this is part of being human.</p></li></ol><p>**Example:** "I''m such an idiot for making that mistake" → "I made a mistake, which shows I''m pushing myself to try new things. What can I learn from this?"</p><p>Share your reframes and reflect: How does it feel to speak to yourself differently?</p>', 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5559, 2343, 1, 'reading', 'What Having a ''Growth Mindset'' Actually Means', 'https://hbr.org/2016/01/what-having-a-growth-mindset-actually-means', '<p>Stanford psychologist Carol Dweck clarifies common misconceptions about growth mindset and explains how to apply it effectively in professional contexts. This article provides crucial foundation for understanding how mindset principles translate into real-world action.</p>', 'Carol Dweck', '2016-01-13', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5560, 2343, 2, 'reading', 'How a Growth Mindset Can Enhance Romantic Relationships', 'https://www.psychologytoday.com/us/blog/beyond-school-walls/202406/how-a-growth-mindset-can-enhance-romantic-relationships', '<p>Explore how growth mindset principles can transform your interpersonal relationships by fostering better communication, resilience, and mutual support. Learn practical strategies for applying mindset concepts to strengthen connections with others.</p>', 'Jessica Koehler', '2024-06-07', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5561, 2343, 3, 'reading', 'Growing a Growth Mindset: How and Why Undergraduate Students'' Mindsets Change', 'https://link.springer.com/article/10.1186/s40594-020-00227-2', '<p>This research study examines how students'' mindsets develop and change over time in academic settings. Understanding these patterns will help you recognize and navigate your own mindset shifts across different life domains.</p>', 'Lisa B. Limeri, Nathan T. Carter, Hannah G. Harper', '2020-07-08', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5562, 2343, 4, 'exercise', 'Growth Mindset Application Mapping', NULL, NULL, NULL, NULL, NULL, '<p>Create a personal "mindset map" for three different areas of your life:</p><ol><li><p>**Academic/Work Context**: Identify one current challenge in your studies or career. Write down your initial fixed-mindset thoughts, then reframe them using growth mindset language. Set one SMART goal with specific action steps.</p></li><li><p>**Relationship Context**: Reflect on a relationship struggle (friend, family, or romantic). How might a growth mindset change your approach? Write a short dialogue showing the difference between fixed and growth mindset responses.</p></li><li><p>**Personal Development**: Choose one skill or ability you''ve been avoiding. Create a 4-week practice plan that focuses on effort and learning rather than immediate perfection.</p></li></ol><p>For each area, identify concrete strategies you''ll use and how you''ll track your progress.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5563, 2344, 1, 'reading', 'Reflective Practice: Models and Process', 'https://www.businessballs.com/self-awareness/reflective-practice/', '<p>Learn about structured models for reflective practice that support continuous learning and self-development. This framework will help you systematically examine your growth mindset journey and extract meaningful insights from your experiences.</p>', 'BusinessBalls.com', '2015-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4594, 1274, 1, 'reading', 'The single biggest reason why start-ups succeed | Bill Gross | TED', 'https://www.youtube.com/watch?v=bNpx7gpSqbY', '<p>Learn the core framework for achieving product-market fit with minimal resources through the Build-Measure-Learn loop and MVP approach.</p>', 'TED', '2015-06-01', 'Youtube video', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4595, 1274, 2, 'reading', 'Bootstrapping Guide for Startups: Economic Principles', 'https://stripe.com/resources/more/the-bootstrapping-guide-for-startups-what-entrepreneurs-need-to-know', '<p>Understand the fundamental economic principles of bootstrapping, including lean operations, reinvesting profits, and achieving self-sustainability without external capital.</p>', 'Stripe', '2024-09-15', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4596, 1274, 3, 'reading', 'Bootstrapping Techniques and New Venture Emergence', 'https://www.researchgate.net/publication/262766376_Bootstrapping_techniques_and_new_venture_emergence', '<p>Academic research examining how bootstrapping techniques enable startup emergence and the relationship between resource acquisition strategies and venture success.</p>', 'Journal of Business Venturing', '2011-03-01', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4597, 1274, 4, 'exercise', 'Map Your Bootstrapped Launch Strategy', NULL, NULL, NULL, NULL, NULL, '<p>Design your startup''s bootstrapped launch plan:</p><ol><li><p>Define your MVP: What is the simplest version of your product that solves a core customer problem?</p></li><li><p>List 5 bootstrapping techniques you''ll use (e.g., personal savings, customer pre-payments, bartering services)</p></li><li><p>Calculate your minimum monthly costs to operate for 6 months</p></li><li><p>Identify 3 ways to validate market demand before building (customer interviews, landing page signups, pre-orders)</p></li><li><p>Create a 90-day timeline showing when you expect first revenue</p></li></ol><p>Be specific and realistic about your constraints and assumptions.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4598, 1275, 1, 'reading', '🧠 Zuckerberg: DON&#39;T just start a company!                      #technology #business #tech #startup', 'https://www.youtube.com/watch?v=2F6YD_xBi-4', '<p>Explore value-based, cost-plus, and competitor-based pricing strategies, and learn how pricing models directly impact revenue growth and customer acquisition.</p>', 'Renji Bijoy', '2023-05-29', 'Youtube video', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4599, 1275, 2, 'reading', 'Unit Economics: Critical to Sustainable Growth', 'https://cfobridge.com/resources/why-understanding-unit-economics-is-critical-to-sustainable-growth', '<p>Master the fundamentals of unit economics—understanding revenue and costs per customer—to ensure your business model is profitable before scaling.</p>', 'CFO Bridge', '2025-06-16', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4600, 1275, 3, 'reading', 'Bootstrapping to $1M: Real-World Revenue Strategy', 'https://buffer.com/resources/bootstrapping-a-business/', '<p>Case study of how one company reached $1M revenue in 18 months through strategic pricing, cash flow management, and profit-first thinking while bootstrapped.</p>', 'Buffer', '2024-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4601, 1275, 4, 'exercise', 'Build Your Revenue Model and Unit Economics', NULL, NULL, NULL, NULL, NULL, '<p>Create a sustainable revenue model for your startup:</p><ol><li><p>Choose your revenue model (subscription, transaction, freemium, etc.) and justify why it fits your product</p></li><li><p>Set your initial pricing: Calculate costs per customer, add target profit margin, compare to competitor pricing</p></li><li><p>Map unit economics:</p><ul><li><p>Customer Acquisition Cost (CAC)</p></li><li><p>Average Revenue Per User (ARPU)</p></li><li><p>Gross margin per customer</p></li><li><p>Customer Lifetime Value (LTV)</p></li></ul></li><li><p>Determine your break-even point: How many customers do you need to cover monthly costs?</p></li><li><p>Project cash flow for months 1-6 with conservative revenue assumptions</p></li></ol><p>Your goal: prove you can be profitable on day one with proper pricing.</p>', 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4602, 1276, 1, 'reading', '🧠 Zuckerberg: DON&#39;T just start a company!                      #technology #business #tech #startup', 'https://www.youtube.com/watch?v=2F6YD_xBi-4', '<p>Understand the critical signals that indicate it''s time to hire your first employee and which roles to prioritize when you have limited capital. This article provides practical frameworks for determining readiness and making strategic hiring decisions.</p>', 'Renji Bijoy', '2023-05-29', 'Youtube video', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4603, 1276, 2, 'reading', 'A Bootstrapper''s Formula For Hiring Your First Employee', 'https://briancasel.com/hiring-your-first-employee', '<p>Learn the ''20-hour rule'' for determining when you''re truly ready to hire and how to avoid the common mistake of hiring before you have enough repeatable work. This founder shares hard-won lessons from hiring too early and the framework that led to success.</p>', 'Brian Casel', '2024-01-01', 'Blog/Article', NULL, 18) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (55, 16, 5, 'reading', 'AI-Assisted Coding in 2026: How GitHub Copilot and Cursor and Amazon Q Are Reshaping Developer Workflows', 'https://www.javacodegeeks.com/2025/12/ai-assisted-coding-in-2026-how-github-copilot-cursor-and-amazon-q-are-reshaping-developer-workflows.html', 'Analysis of how AI tools are changing development practices including security considerations.', 'Java Code Geeks', '2025-12-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (61, 17, 4, 'reading', 'A Beginners Guide to Coding with AI', 'https://www.microsoft.com/en-us/microsoft-copilot/for-individuals/do-more-with-ai/general-ai/a-beginners-guide-to-coding-with-ai/', 'Official Microsoft guide on using Copilot effectively including prompting best practices.', 'Microsoft', '2025-11-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4604, 1276, 3, 'reading', 'Venture capital and the delegation of decision authority in startups: an exploratory study', 'https://link.springer.com/article/10.1007/s40812-024-00313-4', '<p>This academic study examines how startups centralize decision authority and the role delegation plays in organizational design. Essential reading for understanding the strategic implications of maintaining control versus empowering team members as you scale.</p>', 'Journal of Industrial and Business Economics', '2024-05-09', 'Journal Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (114, 25, 3, 'reading', 'Typography in Design: Key Concepts and Principles', 'https://typetype.org/blog/what-is-typography-in-graphic-design-key-concepts-principles-and-examples/', 'Covers font pairing and leading and modular grids and how typography affects layout.', 'TypeType', '2025-10-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5564, 2344, 2, 'reading', 'Habit Formation and Behavior Change', 'https://oxfordre.com/psychology/display/10.1093/acrefore/9780190236557.001.0001/acrefore-9780190236557-e-129', '<p>This academic article explores the psychology of habit formation and how to make new behaviors sustainable over time. Understanding these principles is essential for translating your growth mindset into lasting change.</p>', 'Benjamin Gardner, Amanda L. Rebar', '2019-04-26', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4605, 1276, 4, 'exercise', 'Your First Hire Decision Matrix', NULL, NULL, NULL, NULL, NULL, '<p>Create your hiring readiness assessment and action plan:</p><ol><li><p><strong>Audit Your Time</strong>: Track all tasks you perform for one week. Categorize each as: Strategic (only you), High-skill repeatable (could train someone), or Low-skill repeatable (delegate immediately).</p></li><li><p><strong>Calculate Your ''20-Hour Threshold''</strong>: List all repeatable tasks you could delegate. Estimate weekly hours for each. Do they total 20+ hours/week?</p></li><li><p><strong>Design Your First Role</strong>: Based on your audit, define one specific role. Include: 3-5 core responsibilities, required skills, and success metrics for the first 90 days.</p></li><li><p><strong>Budget Reality Check</strong>: Calculate the true cost (salary + benefits + tools + your training time). Can your current revenue support this for 12+ months?</p></li></ol><p>Submit your time audit summary, role definition, and go/no-go decision with reasoning.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4606, 1277, 1, 'reading', 'The single biggest reason why start-ups succeed | Bill Gross | TED', 'https://www.youtube.com/watch?v=bNpx7gpSqbY', '<p>Explore the anti-patterns that quietly undermine bootstrapped startups—from trying to fix churn with friction to choosing business models that force you into unsustainable corners. This practical guide identifies choices that look reasonable early on but tax you for the next 18 months.</p>', 'TED', '2015-06-01', 'Youtube video', NULL, 22) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4607, 1277, 2, 'reading', 'Pivot or Persevere? How to Make Startup Decisions That Drive Success', 'https://www.thinslices.com/insights/pivot-or-persevere-make-startup-decisions-that-drive-success', '<p>Master the frameworks for making one of entrepreneurship''s toughest decisions: when to change course versus when to stay the path. Learn how to base pivot-or-persevere decisions on evidence rather than emotion, with real-world examples from Instagram, Slack, and other successful pivots.</p>', 'Thinslices', '2024-12-10', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4608, 1277, 3, 'reading', 'The Lean Startup Framework: Closing the Academic–Practitioner Divide', 'https://journals.sagepub.com/doi/10.1177/1042258719899415', '<p>This academic study examines the pivot-or-persevere decision through the lens of entrepreneurship research, exploring psychological ownership, resistance to change, and the empirical evidence on business model refinement. Essential for understanding the cognitive and strategic dimensions of founder decision-making under uncertainty.</p>', 'Dean A. Shepherd, Marc Gruber', '2021-01-01', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (827, 196, 1, 'reading', 'The Ultimate Guide to Startup Funding Stages', 'https://visible.vc/blog/startup-funding-stages/', '<p>Comprehensive overview of funding stages from pre-seed to IPO, including typical amounts raised at each stage and what investors look for. Essential foundation for understanding the venture capital landscape.</p>', 'Visible.vc', '2023-01-15', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4609, 1277, 4, 'exercise', 'Risk Assessment & Decision Framework for Your Venture', NULL, NULL, NULL, NULL, NULL, '<p>Build your personal risk management and decision-making system:</p><ol><li><p><strong>Identify Your Top 5 Risks</strong>: List the biggest threats to your startup''s survival in the next 12 months. For each, rate likelihood (1-5) and impact (1-5).</p></li><li><p><strong>Create Mitigation Strategies</strong>: For your top 3 risks (highest likelihood × impact scores), write specific actions you can take now to reduce either likelihood or impact.</p></li><li><p><strong>Design Your Pivot-or-Persevere Criteria</strong>: Answer these questions for your current business model:</p><ul><li><p>What metric would prove you''re wrong? (Set a specific threshold)</p></li><li><p>What timeline will you give this before reassessing? (Be realistic)</p></li><li><p>What would a pivot look like? (Describe 1-2 alternative directions)</p></li></ul></li><li><p><strong>Decision Commitment</strong>: Write a brief statement committing to your next quarterly review date and the specific data you''ll evaluate.</p></li></ol><p>Submit your risk matrix, mitigation plans, and pivot criteria.</p>', 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5565, 2344, 3, 'reading', 'Personal Growth and Wellbeing: An Iterative Mindset Assessment and Perspective', 'https://www.mdpi.com/2076-328X/15/7/906', '<p>This research introduces the concept of an iterative mindset—the belief that making adaptations and learning from failures is critical for lasting transformation. Discover how to turn setbacks into stepping stones on your continuous growth journey.</p>', 'Kyra Bobinet, Jeni L. Burnette, Wade Becker, Monica Rowell', '2025-07-04', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5566, 2344, 4, 'exercise', 'Personal Growth Plan: Building Your Sustainable Growth Framework', NULL, NULL, NULL, NULL, NULL, '<p>Create a comprehensive personal growth plan that integrates everything you''ve learned:</p><p>**Part 1 - Reflective Assessment** (15 min):</p><p>Reflect on your growth mindset journey. What has shifted in your thinking? Identify 2-3 specific examples where you''ve applied growth mindset principles.</p><p>**Part 2 - Habit Design** (20 min):</p><p>Design 3 growth-supporting habits you''ll practice daily/weekly. For each habit, specify:</p><ul><li><p>The exact behavior</p></li><li><p>When and where you''ll do it (context cues)</p></li><li><p>How you''ll track progress</p></li></ul><p>**Part 3 - Failure Management System** (15 min):</p><p>Create your personal "setback protocol"—specific steps you''ll take when facing challenges or failures to maintain your growth mindset.</p><p>**Part 4 - 90-Day Vision** (10 min):</p><p>Write a brief narrative describing yourself 90 days from now, having sustained these practices. How will your approach to learning, challenges, and relationships have evolved?</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5346, 1602, 1, 'reading', 'IP from the Ancient to the Modern Age', 'https://www.euipo.europa.eu/en/news/ip-from-the-ancient-to-the-modern-age', '<p>Trace intellectual property from ancient Greece and Rome through the Renaissance to modern times. This overview establishes how societies have long valued and protected creative works, setting the foundation for understanding why IP matters.</p>', 'EUIPO', '2020-01-15', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5347, 1602, 2, 'reading', 'Introduction to IP: Crash Course Intellectual Property #1', 'https://www.youtube.com/watch?v=RQOJgEA5e1k', '<p>An engaging introduction to what intellectual property is and why it pervades every aspect of modern life. Muller explores the balance between protecting creators and enabling information sharing in the digital age.</p>', 'Stan Muller', '2015-04-23', 'Youtube video', NULL, 12) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5348, 1602, 3, 'reading', 'Intellectual Property', 'https://plato.stanford.edu/entries/intellectual-property/', '<p>A scholarly examination of IP''s legal history and philosophical foundations, from the Statute of Monopolies to modern systems. This reading deepens your understanding of the core concepts and justifications that underpin IP protection.</p>', 'Adam D. Moore', '2011-03-08', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5349, 1602, 4, 'exercise', 'IP Timeline & Reflection', NULL, NULL, NULL, NULL, NULL, '<p>Create a visual timeline showing 5-7 key milestones in intellectual property history (from ancient times to present). For each milestone, note:</p><ul><li><p>What was protected and why</p></li><li><p>The societal conditions that made this protection necessary</p></li></ul><p>Then write 2-3 paragraphs reflecting on: Which historical justification for IP protection resonates most with you today, and why? How might early IP concepts apply (or fail to apply) to modern digital creations like software, memes, or AI-generated art?</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5350, 1603, 1, 'reading', 'Trademark, Patent, or Copyright', 'https://www.uspto.gov/trademarks/basics/trademark-patent-copyright', '<p>An authoritative overview from the USPTO explaining the key differences between trademarks, patents, and copyrights. This foundational reading clarifies what each type of IP protects and why choosing the right protection matters for your intellectual creations.</p>', 'United States Patent and Trademark Office', '2020-06-15', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5351, 1603, 2, 'reading', 'Patents, Novelty, and Trolls: Crash Course Intellectual Property #4', 'https://www.youtube.com/watch?v=RrN7IxvAJto', '<p>An engaging video exploring how patents protect inventions, what makes something patentable, and the controversies surrounding patent trolls. Muller uses practical examples to show how patent law shapes innovation and business strategy.</p>', 'Stan Muller', '2015-05-14', 'Youtube video', NULL, 11) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5352, 1603, 3, 'reading', 'Copyright vs Patent vs Trademark', 'https://copyrightalliance.org/faqs/difference-copyright-patent-trademark/', '<p>A clear comparison guide that includes trade secrets alongside the main IP types. Learn how these protections differ in scope, requirements, duration, and when multiple forms of IP might protect different aspects of the same creation.</p>', 'Copyright Alliance', '2024-11-27', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5353, 1603, 4, 'exercise', 'IP Protection Strategy Map', NULL, NULL, NULL, NULL, NULL, '<p>Choose a real-world product or service (e.g., a smartphone, restaurant chain, software app, or book). Research and create a detailed map showing:</p><ul><li><p>Which parts are protected by patents (and what type)</p></li><li><p>What elements use trademark protection</p></li><li><p>Which aspects have copyright protection</p></li><li><p>Any potential trade secrets involved</p></li></ul><p>Then write 2 paragraphs explaining: Why does this business need multiple types of IP protection? What would happen if one type of protection were missing? Include at least one example of how different IP types work together to create comprehensive protection.</p>', 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5354, 1604, 1, 'reading', 'Understanding Intellectual Property (IP)', 'https://www.youtube.com/watch?v=UqZJPuyK9VY', '<p>This official WIPO summary introduces you to the foundational international organization for intellectual property. Learn about WIPO''s origins, objectives, and role in administering global IP treaties.</p>', 'Federallabs', '2019-03-27', 'Youtube video', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5355, 1604, 2, 'reading', 'Indigenous/Traditional Knowledge & Intellectual Property: Introduction', 'https://web.law.duke.edu/cspd/itkpaper2/', '<p>This Duke Law paper examines the complex relationship between indigenous knowledge and Western intellectual property systems. Explore how different cultures conceptualize ownership and the challenges of protecting traditional knowledge globally.</p>', 'Jane Anderson', '2010-01-01', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5356, 1604, 3, 'reading', 'Intellectual Property Rights in China—A Literature Review on the Public''s Perspective', 'https://www.frontiersin.org/journals/sociology/articles/10.3389/fsoc.2022.793165/full', '<p>This academic article explores how cultural, political, and economic factors shape public perceptions of IP in China versus Western countries. Understand how cultural values influence IP enforcement and compliance across different societies.</p>', 'Frontiers in Sociology', '2022-03-11', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5357, 1604, 4, 'exercise', 'Cultural IP Perspectives Comparison', NULL, NULL, NULL, NULL, NULL, '<p><strong>Compare IP approaches across cultures:</strong></p><ol><li><p>Choose two countries from different regions (e.g., USA, China, India, or a Pacific Island nation)</p></li><li><p>Research how each country approaches one type of IP protection (patents, trademarks, or traditional knowledge)</p></li><li><p>Create a comparison chart identifying:</p><ul><li><p>Key legal frameworks and treaties each has adopted</p></li><li><p>Cultural values that influence their IP approach</p></li><li><p>At least one example of how IP disputes are handled differently</p></li></ul></li><li><p>Write 2-3 paragraphs reflecting on why these differences exist and what challenges they create for international IP protection.</p></li></ol>', 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5571, 2481, 1, 'reading', 'Philosophy of Education - Stanford Encyclopedia', 'https://plato.stanford.edu/entries/education-philosophy/', 'Comprehensive overview of educational philosophy from ancient Greece to contemporary debates. Essential foundation for the syllabus.', 'Stanford Encyclopedia of Philosophy', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5572, 2481, 2, 'reading', 'The Philosopher King: Education in Plato''s Republic', 'https://medium.com/@arthurboyer/the-philosopher-king-education-in-platos-republic-7d07409f0c1a', 'How Plato designed a 35-year education for guardians culminating in knowledge of the Form of the Good.', 'Medium', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5573, 2481, 3, 'reading', 'Education in Plato''s Republic - Santa Clara University', 'https://www.scu.edu/character/resources/education-in-platos-republic/', 'The Allegory of the Cave as a model for education - liberation from ignorance toward understanding of reality.', 'Santa Clara University', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5574, 2481, 4, 'reading', 'Aristotle on Education - Britannica', 'https://www.britannica.com/topic/philosophy-of-education', 'Aristotle''s emphasis on virtue development through community-guided practice and moral character formation.', 'Britannica', NULL, 'Encyclopedia', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5569, 2349, 1, 'reading', '', NULL, NULL, NULL, NULL, NULL, NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5570, 2349, 2, 'exercise', '', NULL, NULL, NULL, NULL, NULL, NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5575, 2481, 5, 'reading', 'Rousseau''s Emile - Representing Childhood', 'https://www.representingchildhood.pitt.edu/rousseau.htm', 'Rousseau''s revolutionary child-centered approach: ''Everything is good as it leaves the hands of the Author of things.''', 'University of Pittsburgh', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5576, 2481, 6, 'reading', 'Rousseau''s Errors in Educational Theory', 'https://www.psychologytoday.com/us/blog/freedom-learn/200902/rousseau-s-errors-they-persist-today-in-educational-theory', 'Critical analysis: the vulnerable-child fallacy and controllability fallacy in Rousseau''s thinking.', 'Psychology Today', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5577, 2481, 7, 'exercise', 'Classical Philosophy Comparison', NULL, 'Write a 500-word essay comparing Plato, Aristotle, and Rousseau on the fundamental purpose of education. Which philosopher''s vision most resonates with your own experience?', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5578, 2482, 1, 'reading', 'Dewey''s Educational Philosophy - The Education Hub', 'https://theeducationhub.org.nz/deweys-educational-philosophy/', 'Dewey''s pragmatism: cultivating thoughtful, critically reflective individuals through experience rather than rote learning.', 'The Education Hub', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5579, 2482, 2, 'reading', 'John Dewey - Stanford Encyclopedia', 'https://plato.stanford.edu/entries/dewey/', 'Comprehensive overview of Dewey''s philosophy including his landmark ''Democracy and Education'' (1916).', 'Stanford Encyclopedia of Philosophy', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5580, 2482, 3, 'reading', 'Dewey and Citizenship Education', 'https://www.researchgate.net/publication/336609987_Dewey_and_Citizenship_Education_Schooling_as_Democratic_Practice', 'How education and democracy are organically connected - each serving as a condition for the other.', 'ResearchGate', NULL, 'Academic Paper', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5581, 2482, 4, 'reading', 'Newman on Education - Cardinal Newman Society', 'https://cardinalnewmansociety.org/newman-on-education/', 'Newman''s vision: liberal education as ''real cultivation of mind'' - a connected view and grasp of things.', 'Cardinal Newman Society', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5582, 2482, 5, 'reading', 'The Idea of a University - Newman Reader', 'https://www.newmanreader.org/works/idea/discourse7.html', 'Newman''s Discourse VII: Knowledge as its own end - the intellect disciplined for its own sake, not for specific trades.', 'Newman Reader', NULL, 'Primary Source', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5583, 2482, 6, 'reading', 'A Remedy to Misconceptions: Newman''s Idea of a University', 'https://www.wordonfire.org/articles/a-remedy-to-misconceptions-newmans-the-idea-of-a-university/', 'The university''s purpose is to train minds to comprehend truth - it makes thinkers, not saints.', 'Word on Fire', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5584, 2482, 7, 'exercise', 'Analyze Your Educational Experience', NULL, 'Reflect on your own education through Dewey''s and Newman''s lenses. Did it prepare you for democratic citizenship? Did it cultivate your mind for its own sake? Write a personal analysis (600 words).', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5585, 2483, 1, 'reading', 'Education in Ancient Greece - Wikipedia', 'https://en.wikipedia.org/wiki/Education_in_ancient_Greece', 'From elementary grammatistes to Plato''s Academy - how the Greeks invented formal education.', 'Wikipedia', NULL, 'Encyclopedia', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5586, 2483, 2, 'reading', 'Ancient Higher Education - Philosophy of Education', 'https://www.tandfonline.com/doi/full/10.1080/00131857.2018.1553490', 'Plato''s Academy (387 BCE), Aristotle''s Lyceum (335 BCE), and the Imperial University of Constantinople (425 CE).', 'Taylor & Francis', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5587, 2483, 3, 'reading', 'Athens: Elementary and Higher Education - Britannica', 'https://www.britannica.com/topic/education/Athens', 'The three masters of Greek elementary education and how the Sophists revolutionized higher learning.', 'Britannica', NULL, 'Encyclopedia', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5588, 2483, 4, 'reading', 'Medieval Universities - Vaia', 'https://www.vaia.com/en-us/explanations/history/modern-world-history/medieval-universities/', 'The seven liberal arts: trivium (grammar, rhetoric, logic) and quadrivium (arithmetic, astronomy, geometry, music).', 'Vaia', NULL, 'Educational Resource', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5589, 2483, 5, 'reading', 'What Did Medieval Universities Teach?', 'https://www.historyhit.com/what-did-european-universities-teach-during-the-middle-ages/', '8-9 years for liberal arts, then theology, medicine, or law. How Aristotle became central to Scholasticism.', 'History Hit', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5590, 2483, 6, 'reading', 'History of College - From Bologna to Today', 'https://www.myfrontpagestory.com/history-of-college/', 'Bologna (1088), Paris (1150), Oxford (1167) - how medieval institutions shaped modern universities.', 'My Front Page Story', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5591, 2483, 7, 'exercise', 'Curriculum Evolution Map', NULL, 'Create a visual timeline showing how educational curriculum evolved from the trivium/quadrivium to modern disciplines. Identify which classical subjects survive and which disappeared.', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5592, 2484, 1, 'reading', 'MOOCs Didn''t Achieve Their Goals - Inside Higher Ed', 'https://www.insidehighered.com/digital-learning/article/2019/01/16/study-offers-data-show-moocs-didnt-achieve-their-goals', 'MIT/Harvard study: completion rates barely budged, 68.7% of students from developed countries. The democratization promise unfulfilled.', 'Inside Higher Ed', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5593, 2484, 2, 'reading', 'The MOOC Problem - Hybrid Pedagogy', 'https://hybridpedagogy.org/mooc-problem/', 'Critical analysis: MOOCs underperformed traditional models with no large-scale cost benefit despite the hype.', 'Hybrid Pedagogy', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5594, 2484, 3, 'reading', 'MOOCs and Technology Access Barriers', 'https://www.researchgate.net/publication/319117280_MOOCS''_Potential_for_Democratizing_Education_An_Analysis_from_the_Perspective_of_Access_to_Technology', 'How technology access limits MOOCs'' democratizing potential - governmental action needed for equity.', 'ResearchGate', NULL, 'Academic Paper', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5595, 2484, 4, 'reading', 'Contextualizing Khan Academy - World Bank', 'https://blogs.worldbank.org/en/education/contextualizing-khan-academy', 'The Matthew Effect in edtech: the best teachers get the greatest impact, flexibility can harm low-capacity systems.', 'World Bank Blogs', NULL, 'Blog/Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5596, 2484, 5, 'reading', 'Con Academy - Hedgehog Review', 'https://hedgehogreview.com/issues/after-neoliberalism/articles/con-academy', 'Critical examination of Khan Academy''s AI hype and the ''technology is not good or bad'' cliché.', 'Hedgehog Review', NULL, 'Academic Article', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5597, 2484, 6, 'reading', 'Epistemology and Education', 'https://www.encyclopedia.com/education/applied-and-social-sciences-magazines/epistemology-and-education', 'How theories of knowledge shape educational practice - from justified true belief to constructivism.', 'Encyclopedia.com', NULL, 'Encyclopedia', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5598, 2484, 7, 'exercise', 'EdTech Democratization Audit', NULL, 'Choose an educational platform (Coursera, Khan Academy, Duolingo, etc.) and evaluate its democratization claims. Who actually benefits? What barriers remain? Present your findings in a 2-page analysis.', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5358, 1605, 1, 'reading', 'Licensing Intellectual Property 101: What Every Entrepreneur and Business Owner Should Know', 'https://www.aipla.org/list/innovate-articles/licensing-intellectual-property-101-what-every-entrepreneur-and-business-owner-should-know', '<p>This AIPLA article introduces the fundamentals of IP licensing agreements, covering essential terms and negotiations. Learn the practical aspects of how IP owners monetize their assets while retaining ownership through strategic licensing arrangements.</p>', 'American Intellectual Property Law Association', '2020-01-15', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5359, 1605, 2, 'reading', 'Intersections Between Intellectual Property and Dispute Resolution', 'https://academic.oup.com/book/41122/chapter/350440367', '<p>This Oxford Academic chapter explores civil adjudication and alternative dispute resolution (ADR) for IP disputes. Understand the mechanisms available for resolving IP conflicts, from traditional litigation to mediation and arbitration, and the strategic considerations for each approach.</p>', 'Oxford University Press', '2021-05-20', 'Book Chapter', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5360, 1605, 3, 'reading', 'AI Copyright Infringement Detection', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', '<p>This video explains how modern technology, including AI systems like YouTube''s Content ID, automatically detects copyright infringement at scale. Explore real-world examples of how companies monitor and enforce their IP rights using automated detection tools and DMCA takedown processes.</p>', 'Filevine', '2024-06-15', 'Youtube video', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5361, 1605, 4, 'exercise', 'IP Enforcement Strategy Simulation', NULL, NULL, NULL, NULL, NULL, '<p><strong>Design an IP enforcement plan for a hypothetical scenario:</strong></p><p>You''ve discovered a competitor is selling products that appear to infringe your company''s trademark and patent. Create a comprehensive enforcement strategy that includes:</p><ol><li><p><strong>Initial Assessment:</strong> Identify which IP rights are infringed (trademark, patent, or both) and gather evidence</p></li><li><p><strong>Enforcement Options:</strong> List 3-4 possible responses (cease-and-desist letter, negotiated license, litigation, online platform reporting)</p></li><li><p><strong>Cost-Benefit Analysis:</strong> For each option, note estimated timeframe, costs, and likelihood of success</p></li><li><p><strong>Recommended Approach:</strong> Choose your strategy and justify it in 2-3 paragraphs</p></li><li><p><strong>Alternative Dispute Resolution:</strong> Explain when mediation or arbitration might be preferable to litigation</p></li></ol><p>Reflect on how different enforcement mechanisms balance protection of your rights with practical business considerations.</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5362, 1686, 1, 'reading', 'Programming in the Age of AI', 'https://bdtechtalks.com/2025/05/12/programming-in-the-age-of-ai/', 'Why learning programming still matters in the AI era. Building deep skills beyond vibe coding for production-ready software.', 'TechTalks', '2025-05-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
