INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5375, 1687, 7, 'exercise', 'Animated Landing Page', NULL, 'Create a landing page with multiple CSS animations including fade-ins and hover effects and looping decorations.', NULL, NULL, NULL, 'Create a landing page with at least 3 CSS animations: (1) a fade-in header on page load (2) a button with hover transition effects (3) a looping animation for a decorative element. Use CSS Grid or Flexbox for layout.', 90) ON CONFLICT DO NOTHING;
