INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5378, 1688, 3, 'reading', 'W3Schools JavaScript Tutorial', 'https://www.w3schools.com/js/', 'Interactive JavaScript tutorial covering basics through ES2025. Try it Yourself examples throughout.', 'W3Schools', '2025-01-01', 'Blog/Article', NULL, 60) ON CONFLICT DO NOTHING;
