INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5380, 1688, 5, 'reading', 'Fireship JavaScript Course', 'https://fireship.io/courses/js/', 'Modern JavaScript with vanilla JS - no frameworks. Beginner-friendly with Fireship-style humor and projects.', 'Fireship (Jeff Delaney)', '2024-01-01', 'Blog/Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5381, 1688, 6, 'exercise', 'Interactive To-Do List', NULL, 'Build a functional to-do app with vanilla JavaScript using DOM manipulation.', NULL, NULL, NULL, 'Build a to-do list app with vanilla JavaScript: (1) Add new tasks (2) Mark tasks complete with strikethrough (3) Delete tasks (4) Tasks persist visually until page refresh. Use DOM manipulation - no frameworks.', 90) ON CONFLICT DO NOTHING;
