INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1625, 361, 3, 'reading', 'Vibe Coding is Not the Same as AI-Assisted Engineering', 'https://medium.com/@addyosmani/vibe-coding-is-not-the-same-as-ai-assisted-engineering-3f81088d5b98', 'Critical distinction between casual AI prompting and disciplined AI-augmented workflows.', 'Addy Osmani', '2025-11-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
