INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1627, 361, 5, 'reading', 'Awesome Vibe Coding Guide (GitHub)', 'https://github.com/analyticalrohit/awesome-vibe-coding-guide', 'Community-curated best practices for efficient AI-assisted coding.', 'analyticalrohit', '2025-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1628, 361, 6, 'reading', 'AI-Assisted Software Development and the Vibe Coding Debate', 'https://cybersecurityadvisors.network/2025/08/06/ai-assisted-software-development-and-the-vibe-coding-debate-by-nick-kelly/', 'Critical analysis of code quality risks in vibe coding.', 'Nick Kelly', '2025-08-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
