INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1630, 362, 1, 'reading', 'The Developer Guide to Design Tokens and CSS Variables', 'https://penpot.app/blog/the-developers-guide-to-design-tokens-and-css-variables/', 'Foundational explainer on the difference between design tokens and CSS custom properties.', 'Penpot', '2025-12-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1631, 362, 2, 'reading', 'Design Systems Handbook: Chapter 1 - Introducing Design Systems', 'https://www.designbetter.co/design-systems-handbook', 'Free handbook from InVision covering design system foundations. Chapter 1 explains why design systems matter and how they reduce design debt.', 'Marco Suarez and Jina Anne and Katie Sylor-Miller', '2017-01-01', 'Book Chapter', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5386, 1689, 5, 'reading', 'The Real 2025 Guide to Picking Your First JavaScript Framework', 'https://clinkitsolutions.com/react-vs-vue-vs-svelte-the-real-2025-guide-to-picking-your-first-javascript-framework/', 'Practical guide for beginners choosing their first framework. React for jobs and Vue for comfort and Svelte for joy.', 'ClinkIT Solutions', '2025-11-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5387, 1689, 6, 'exercise', 'Framework Exploration Report', NULL, 'Complete an official framework tutorial and write a reflection comparing it to vanilla JS.', NULL, NULL, NULL, 'Pick ONE framework (React or Vue or Svelte) and complete its official tutorial. Write a 500-word reflection: What did you build? What concepts were new? How does it compare to vanilla JS? Would you use it for your next project and why?', 120) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1632, 362, 3, 'reading', 'Using Design Tokens as Variables: Best Practices', 'https://designtokens.substack.com/p/using-design-tokens-as-variables', 'Deep dive on implementing tokens in three layers: primitives to semantic aliases to component slots.', 'Design Tokens Newsletter', '2025-11-01', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1633, 362, 4, 'reading', 'Design Tokens Naming Structure', 'https://medium.com/@brcsndr/you-dont-know-css-design-tokens-naming-structure-52add5d02682', 'Practical naming convention guide using Component-Variant-Kind-Modifier-Property structure.', 'Bryce Snyder', '2023-11-01', 'Blog/Article', NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (828, 196, 2, 'reading', 'Financial Projections for Startups: Guide and Template', 'https://graphitefinancial.com/blog/financial-projections-for-startups-guide-and-template/', '<p>Learn how to create realistic financial projections including income statements, cash flow statements, and break-even analysis. Includes practical examples and templates for building credible forecasts that investors expect to see.</p>', 'Graphite Financial', '2025-02-17', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (829, 196, 3, 'reading', 'Bootstrapping vs. Venture Capital: Which Funding is Best?', 'https://www.rho.co/blog/bootstrapping-vs-venture-capital', '<p>Compare the tradeoffs between bootstrapping and venture capital funding, including impacts on ownership, control, and growth speed. Understand alternative funding strategies like crowdfunding and revenue-based financing.</p>', 'Rho', '2025-06-27', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (830, 196, 4, 'exercise', 'Create Your Funding Strategy and Financial Pitch', NULL, NULL, NULL, NULL, NULL, '<p>Build a funding strategy presentation for your tech startup idea:</p><ol><li><p>Choose your funding approach (bootstrapping, VC, crowdfunding, or hybrid)</p></li><li><p>Create 3-year financial projections: revenue, expenses, and cash flow (simplified)</p></li><li><p>Design a 5-slide mini pitch deck covering:</p><ul><li><p>Problem & Solution (1 slide)</p></li><li><p>Market Opportunity (1 slide)</p></li><li><p>Business Model & Revenue (1 slide)</p></li><li><p>Financial Ask & Use of Funds (1 slide)</p></li><li><p>Team & Why Now (1 slide)</p></li></ul></li></ol><p>Write a 1-paragraph reflection: What surprised you most about planning your funding strategy?</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (850, 201, 4, 'exercise', 'Build Your Personal Learning System', NULL, NULL, NULL, NULL, NULL, '<p>Create a sustainable framework for continuous learning that works for your life:</p><p>**Part 1: Self-Assessment (15 min)**</p><ul><li><p>What are your top 3 learning strengths and challenges?</p></li><li><p>When and how do you learn best?</p></li></ul><p>**Part 2: System Design (30 min)**</p><ul><li><p>**Weekly Learning Ritual**: When will you dedicate time to learning? (be specific)</p></li><li><p>**Reflection Practice**: How will you track what works? (journal, app, etc.)</p></li><li><p>**Skill Pipeline**: List 3 skills to develop over the next year, in order</p></li><li><p>**Accountability**: How will you maintain momentum?</p></li></ul><p>**Part 3: Integration (15 min)**</p><ul><li><p>Write 3 metacognitive questions you''ll ask yourself after each learning session</p></li><li><p>Identify one way to apply this week''s concepts immediately</p></li></ul><p>The goal: a practical system you''ll actually use beyond this course.</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1634, 362, 5, 'reading', 'How to Use Tokens in Design Systems (LogRocket)', 'https://blog.logrocket.com/ux-design/how-to-use-tokens-in-design-systems/', 'Figma-focused tutorial on creating design variables that export as tokens.', 'Daniel Schwarz', '2024-12-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1635, 362, 6, 'reading', 'What Are Design Tokens? (CSS-Tricks)', 'https://css-tricks.com/what-are-design-tokens/', 'Classic explainer on design tokens as platform-agnostic design decisions.', 'Robin Rendle', '2019-01-01', 'Blog/Article', NULL, 15) ON CONFLICT DO NOTHING;
