INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (831, 197, 1, 'reading', 'Minimum Viable Product (MVP): What is it & how to start', 'https://www.atlassian.com/agile/product-management/minimum-viable-product', '<p>This practical guide introduces the MVP concept and walks through real-world examples like Amazon and Uber. You''ll learn how to validate product ideas with minimal resources before full development—a critical skill for launching your tech venture.</p>', 'Atlassian', '2025-10-29', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (832, 197, 2, 'reading', 'How to Develop a Go-to-Market Strategy for Your Tech Venture', 'https://online.hbs.edu/blog/post/go-to-market-strategy-framework', '<p>Drawing on Harvard Business School''s framework, this article explains how to create an effective go-to-market strategy, including customer acquisition costs and the importance of experimentation. Essential reading for planning your product launch and reaching target customers.</p>', 'Catherine Cote', '2023-07-13', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1643, 363, 6, 'reading', 'From Figma to Production Code in 30 Minutes', 'https://dev.to/__8f10a1a58b86/from-figma-to-production-code-in-30-minutes-a-systematic-ai-assisted-workflow-2nee', 'Step-by-step workflow using shadcn/ui Figma kit.', 'DEV Community', '2025-08-01', 'Blog/Article', NULL, 35) ON CONFLICT DO NOTHING;
