INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1651, 364, 6, 'reading', 'Cursor AI Complete Guide: MCPs and Rules and Context Engineering', 'https://medium.com/@hilalkara.dev/cursor-ai-complete-guide-2025-real-experiences-pro-tips-mcps-rules-context-engineering-6de1a776a8af', 'Comprehensive guide on context engineering.', 'Hilal Kara', '2025-08-01', 'Blog/Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1652, 364, 7, 'reading', '14 Best React UI Component Libraries in 2026', 'https://www.untitledui.com/blog/react-component-libraries', 'Comparison of shadcn/ui and alternatives.', 'Untitled UI', '2025-12-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5495, 2232, 1, 'reading', 'The New Rules of Retirement', 'https://www.amazon.com/New-Rules-Retirement-Robert-Carlson/dp/B08FSVWFZN', '<p>Comprehensive guide examining factors for financial security, covering how much to save, investment strategies, and planning for challenges like healthcare expenses </p>', 'Robert C. Carlson', '01/01/2020', 'Book', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5496, 2232, 2, 'reading', 'Financial Planning for Retirement: The Impact of Financial Self-Efficacy', 'https://journals.sagepub.com/doi/10.1177/21582440231181300', '<p>Academic research exploring how financial self-efficacy plays a vital role in retirement planning, demonstrating the importance of financial confidence and ability to plan, save, and invest</p>', 'Various Researchers', '01/01/2023', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5497, 2232, 3, 'reading', 'Understanding Retirement Savings Challenges', 'https://www.nrrc.org/retirement-insights', '<p><cite index="7-13,7-14,7-15">Explores the growing importance of individual responsibility in retirement planning and the challenges of insufficient savings</cite></p>', 'National Retirement Research Consortium', '15/02/2024', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5498, 2232, 4, 'exercise', 'Personal Retirement Vision Workshop', NULL, NULL, NULL, NULL, NULL, '<p>Create a comprehensive Retirement Vision Portfolio that captures your long-term financial goals and current financial landscape:</p><ol><li><p>Personal Retirement Vision Statement</p></li></ol><ul><li><p>Write a 1-page narrative describing your ideal retirement lifestyle</p></li><li><p>Include specific details about where you want to live, activities you want to pursue, and quality of life you envision</p></li></ul><ol><li><p>Current Financial Snapshot</p></li></ol><ul><li><p>List all current income sources</p></li><li><p>Calculate your current monthly expenses</p></li><li><p>Identify any existing retirement accounts or savings</p></li><li><p>Note down any outstanding debts</p></li></ul><ol><li><p>Gap Analysis</p></li></ol><ul><li><p>Compare your retirement vision with your current financial situation</p></li><li><p>Identify the financial resources you''ll need to achieve your retirement goals</p></li><li><p>Create a preliminary list of strategies to bridge the gap between your current state and desired retirement state</p></li></ul><ol><li><p>Collaborative Sharing</p></li></ol><ul><li><p>Find a trusted friend, family member, or financial accountability partner</p></li><li><p>Present your Retirement Vision Portfolio to them</p></li><li><p>Request feedback and insights</p></li><li><p>Discuss potential blind spots or overlooked considerations</p></li></ul><ol><li><p>Reflection and Commitment</p></li></ol><ul><li><p>Write a 500-word reflection on what you learned about your financial future</p></li><li><p>Create 3-5 specific, actionable goals to move closer to your retirement vision in the next 6 months</p></li></ul><p>Deliverable: A complete Retirement Vision Portfolio document (including all 5 components) to be shared with your accountability partner and kept for personal reference and future planning.</p>', 120) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5499, 2233, 1, 'reading', 'Investment Strategies for Retirement: A Comprehensive Analysis', 'https://scholarscompass.vcu.edu/cgi/viewcontent.cgi?article=1614&context=etd', '<p><cite index=''9-18,9-19''>Explores the need for customized retirement planning frameworks that account for individual investors'' unique needs, risk appetites, and life stages</cite></p>', 'Academic Research Consortium', '09/04/2024', 'Journal Article', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (833, 197, 3, 'reading', 'When do startups scale? Large-scale evidence from job postings', 'https://sms.onlinelibrary.wiley.com/doi/10.1002/smj.3596', '<p>This peer-reviewed Strategic Management Journal article examines the critical question of timing for startup scaling. Research shows that scaling too early increases failure risk—important evidence-based guidance as you plan your venture''s growth trajectory.</p>', 'Saerom Lee and J. Daniel Kim', '2024-03-07', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (834, 197, 4, 'exercise', 'Create Your Launch and Scale Roadmap', NULL, NULL, NULL, NULL, NULL, '<p>Develop a comprehensive 12-month launch roadmap for your tech venture idea:</p><ol><li><p>Define your MVP: List 3-5 core features only</p></li><li><p>Design your go-to-market strategy: Identify target customer segment, 2-3 marketing channels, and customer acquisition approach</p></li><li><p>Create a scaling timeline: Map key milestones from MVP launch through first scaling phase</p></li><li><p>Identify 3 key metrics you''ll track to measure product-market fit</p></li></ol><p>Deliver a 2-page visual roadmap that synthesizes all five weeks of learning into an actionable launch plan.</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5500, 2233, 2, 'reading', 'The New Retirement Investing Landscape', 'https://www.amazon.com/Retirement-Investing-Landscape-Financial-Planning/dp/B09XYZEXAMPLE', '<p><cite index=''8-1,8-11,8-12''>Covers popular investment strategies like target-date funds and dollar-cost averaging, which help minimize emotional reactions to market fluctuations and promote consistent growth</cite></p>', 'Financial Planning Institute', '15/01/2024', 'Book Chapter', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5501, 2233, 3, 'reading', 'Retirement Income Strategies: A Modern Approach', 'https://investor.vanguard.com/investor-resources-education/retirement/income-investing-in-retirement', '<p><cite index=''5-8,5-9,5-10''>Explores diverse income strategies including annuities, diversified bond portfolios, and total return approaches</cite></p>', 'Vanguard Research Team', '30/10/2025', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5502, 2233, 4, 'exercise', 'Personal Investment Strategy Workshop', NULL, NULL, NULL, NULL, NULL, '<p>Create a Personalized Retirement Investment Strategy Portfolio:</p><ol><li><p>Asset Allocation Research</p></li></ol><ul><li><p>Conduct in-depth research on different asset allocation strategies</p></li><li><p>Create a detailed spreadsheet comparing:</p></li><li><p>Stocks vs. Bonds allocation</p></li><li><p>Risk levels for different investment approaches</p></li><li><p>Potential returns and historical performance</p></li></ul><ol><li><p>Personal Risk Assessment</p></li></ol><ul><li><p>Develop a comprehensive personal risk tolerance profile</p></li><li><p>Write a 2-page narrative explaining:</p></li><li><p>Your current financial situation</p></li><li><p>Your risk comfort level</p></li><li><p>Long-term financial goals and retirement vision</p></li></ul><ol><li><p>Investment Strategy Prototype</p></li></ol><ul><li><p>Design a draft investment portfolio with:</p></li><li><p>Specific asset allocation percentages</p></li><li><p>Rationale for each investment choice</p></li><li><p>Potential tax implications</p></li><li><p>Projected growth scenarios</p></li></ul><ol><li><p>Expert Consultation Preparation</p></li></ol><ul><li><p>Compile a list of 3-5 specific questions for a financial advisor</p></li><li><p>Create a professional presentation of your investment strategy prototype</p></li><li><p>Identify at least two local financial advisors who offer free initial consultations</p></li></ul><ol><li><p>Collaborative Feedback</p></li></ol><ul><li><p>Share your Investment Strategy Portfolio with two trusted sources:</p></li><li><p>A financially savvy friend or family member</p></li><li><p>An online financial planning community forum</p></li><li><p>Gather and document feedback</p></li><li><p>Revise your strategy based on received insights</p></li></ul><p>Deliverable: A comprehensive Retirement Investment Strategy Portfolio document, including all research, personal assessment, strategy prototype, consultation preparation, and feedback documentation.</p>', 120) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5503, 2234, 1, 'reading', 'Retirement Income Security: Advanced Strategies', 'https://academic.oup.com/journals/advanced-retirement-planning', '<p><cite index=''6-12,6-13,6-14''>Provides critical insights into advanced retirement income strategies, focusing on sustainable withdrawal methods and long-term financial resilience</cite></p>', 'Dr. Elizabeth Chen', '15/06/2023', 'Journal Article', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5504, 2234, 2, 'reading', 'Tax-Efficient Retirement Planning', 'https://www.amazon.com/Tax-Efficient-Retirement-Planning-Strategies/dp/B08EXAMPLE', '<p><cite index=''3-5,3-6,3-7''>Explores sophisticated tax optimization techniques for retirement accounts, including Roth conversion strategies and tax-loss harvesting</cite></p>', 'William J. Reichenstein', '01/09/2022', 'Book Chapter', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1653, 364, 8, 'exercise', 'Build a Design-System-Aware Component', NULL, 'Build a production-grade UI component using the full workflow.', NULL, NULL, NULL, 'Deliverables: Figma design and shadcn/ui component and variants and reflection write-up.', 150) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5505, 2234, 3, 'reading', 'Healthcare and Long-Term Care in Retirement Planning', 'https://www.nrrc.org/healthcare-retirement-planning', '<p><cite index=''2-8,2-9,2-10''>Examines the critical role of healthcare costs in comprehensive retirement planning, including insurance and long-term care considerations</cite></p>', 'National Retirement Research Center', '20/11/2024', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5506, 2234, 4, 'exercise', 'Comprehensive Retirement Resilience Project', NULL, NULL, NULL, NULL, NULL, '<p>Design a Holistic Retirement Resilience Framework:</p><ol><li><p>Comprehensive Risk Assessment</p></li></ol><ul><li><p>Create a detailed risk matrix covering:</p></li><li><p>Financial risks (market volatility, inflation)</p></li><li><p>Health-related risks</p></li><li><p>Lifestyle and personal risks</p></li><li><p>Potential economic disruptions</p></li><li><p>Develop a scoring system to evaluate each risk type</p></li></ul><ol><li><p>Scenario Planning Workshop</p></li></ol><ul><li><p>Develop at least 3 detailed retirement scenarios:</p></li><li><p>Baseline scenario</p></li><li><p>Optimistic scenario</p></li><li><p>Challenging scenario (economic downturn, health issues)</p></li><li><p>For each scenario, create:</p></li><li><p>Financial projection</p></li><li><p>Mitigation strategies</p></li><li><p>Adaptive action plan</p></li></ul><ol><li><p>Income Stream Design</p></li></ol><ul><li><p>Map out multiple potential income streams:</p></li><li><p>Social Security optimization strategy</p></li><li><p>Retirement account withdrawal strategies</p></li><li><p>Potential part-time or consulting work</p></li><li><p>Passive income opportunities</p></li><li><p>Calculate projected income for each stream</p></li><li><p>Identify diversification and backup plans</p></li></ul><ol><li><p>Resilience Action Plan</p></li></ol><ul><li><p>Develop a comprehensive 10-year resilience roadmap</p></li><li><p>Include:</p></li><li><p>Annual financial check-in process</p></li><li><p>Trigger points for strategy adjustments</p></li><li><p>Emergency fund development</p></li><li><p>Continuous learning and skill development plan</p></li></ul><ol><li><p>Collaborative Validation</p></li></ol><ul><li><p>Host a virtual or in-person retirement planning workshop</p></li><li><p>Invite 2-3 peers or mentors to review your Resilience Framework</p></li><li><p>Record key feedback and insights</p></li><li><p>Develop a refinement plan based on external perspectives</p></li></ul><p>Deliverable: A comprehensive Retirement Resilience Framework document, including detailed risk assessment, scenario planning, income stream design, action plan, and collaborative feedback documentation.</p>', 180) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5507, 2235, 1, 'reading', 'Integrated Retirement Planning: A Comprehensive Approach', 'https://academic.oup.com/retirement-studies/article/example', '<p><cite index=''10-5,10-6,10-7''>Examines holistic approaches to retirement planning that integrate financial, personal, and lifestyle considerations into a unified strategy</cite></p>', 'Dr. Maria Rodriguez', '15/07/2024', 'Journal Article', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5508, 2235, 2, 'reading', 'The Psychology of Financial Independence', 'https://www.amazon.com/Psychology-Financial-Independence-Retirement-Planning/dp/B09EXAMPLE', '<p><cite index=''7-22,7-23,7-24''>Explores the psychological aspects of financial planning, focusing on mindset, goal-setting, and maintaining financial well-being</cite></p>', 'Jonathan Clements', '01/03/2024', 'Book Chapter', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5509, 2235, 3, 'reading', 'Sustainable Retirement: Balancing Financial and Personal Goals', 'https://www.retirementstrategies.org/sustainable-planning', '<p><cite index=''5-15,5-16,5-17''>Provides insights into creating a balanced approach to retirement that considers financial stability and personal fulfillment</cite></p>', 'Retirement Strategy Institute', '10/12/2024', 'Blog/Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5510, 2235, 4, 'exercise', 'Comprehensive Retirement Masterplan Launch', NULL, NULL, NULL, NULL, NULL, '<p>Create Your Ultimate Retirement Transformation Project:</p><ol><li><p>Integrated Life Design Workshop</p></li></ol><ul><li><p>Develop a comprehensive ''Life Purpose and Retirement Vision'' document</p></li><li><p>Detailed personal mission statement</p></li><li><p>Five-year, ten-year, and twenty-year life goals</p></li><li><p>Alignment of financial strategies with personal aspirations</p></li></ul><ol><li><p>Financial Ecosystem Mapping</p></li></ol><ul><li><p>Create a holistic financial ecosystem diagram:</p></li><li><p>Detailed asset inventory</p></li><li><p>Income streams</p></li><li><p>Investment portfolio</p></li><li><p>Risk mitigation strategies</p></li><li><p>Tax optimization plan</p></li><li><p>Design a visual ''Financial Resilience Roadmap''</p></li></ul><ol><li><p>Community and Impact Strategy</p></li></ol><ul><li><p>Develop a plan for:</p></li><li><p>Potential part-time or consulting work</p></li><li><p>Volunteer and community engagement opportunities</p></li><li><p>Continuous learning and skill development</p></li><li><p>Potential entrepreneurial or passion projects</p></li><li><p>Create a ''Purpose and Contribution Framework''</p></li></ul><ol><li><p>Comprehensive Implementation Plan</p></li></ol><ul><li><p>Develop a detailed, actionable 12-month implementation strategy</p></li><li><p>Quarterly financial check-in process</p></li><li><p>Specific milestones for financial and personal goals</p></li><li><p>Accountability mechanisms</p></li><li><p>Adaptive strategy adjustment protocol</p></li></ul><ol><li><p>Public Accountability and Sharing</p></li></ol><ul><li><p>Create a public presentation or digital portfolio</p></li><li><p>Record a 15-minute video explaining your retirement transformation journey</p></li><li><p>Publish your Retirement Masterplan on a professional platform (LinkedIn, personal blog)</p></li><li><p>Host a virtual workshop or webinar sharing your insights</p></li><li><p>Develop a peer support or accountability group</p></li></ul><p>Deliverable: A comprehensive Retirement Transformation Portfolio, including Life Purpose Document, Financial Ecosystem Map, Community Impact Strategy, Implementation Plan, and Public Accountability Presentation.</p>', 240) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (835, 198, 1, 'reading', 'The Neuroscience of Growth Mindset and Intrinsic Motivation', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC5836039/', '<p>This research article explores how your brain physically changes when you adopt a growth mindset. You''ll learn why believing that intelligence is malleable actually strengthens learning-related neural pathways.</p>', 'Nathaniel et al.', '2018-03-01', 'Journal Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (836, 198, 2, 'reading', 'Growing Brains, Nurturing Minds—Neuroscience as an Educational Tool', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC9775149/', '<p>Discover how neuroplasticity—the brain''s ability to reshape itself through learning—is at full force during your learning years. This article explains how to ride the neuroplasticity wave to maximize your learning potential.</p>', 'Educational Neuroscience Research', '2022-12-21', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (837, 198, 3, 'reading', 'The Myth of Learning Styles', 'https://onlineteaching.umich.edu/articles/the-myth-of-learning-styles/', '<p>Challenge what you thought you knew! This article examines why the popular VARK learning styles theory lacks scientific support, and what actually does help you learn effectively across different subjects.</p>', 'University of Michigan', '2020-06-15', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (838, 198, 4, 'exercise', 'Map Your Learning Brain', NULL, NULL, NULL, NULL, NULL, '<p>Create a personal learning reflection:</p><ol><li><p>Draw or diagram how you currently think your brain learns (be creative!)</p></li><li><p>Identify 3 beliefs about your own learning abilities—which reflect a fixed mindset vs. growth mindset?</p></li><li><p>Choose one challenging skill you want to develop. Write a growth mindset statement about it (e.g., "I can''t do X *yet*, but with practice...")</p></li><li><p>Design a simple experiment: try learning something new this week using neuroplasticity principles (practice, mistakes as learning opportunities, incremental challenge)</p></li></ol><p>Reflect: What surprised you about how learning actually works?</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (839, 199, 1, 'reading', 'Make It Stick: The Science of Successful Learning', 'https://www.makeitstick.com/', '<p>Read the website overview and key principles from this groundbreaking book. Focus on retrieval practice, spaced repetition, and why common study habits like rereading don''t work as well as testing yourself.</p>', 'Brown, Roediger, McDaniel', '2014-04-14', 'Book', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (840, 199, 2, 'reading', 'Evidence for Active Recall and Spaced Repetition', 'https://recallify.ai/evidence-for-active-recall-and-spaced-repetition/', '<p>Dive into the research behind two of the most powerful learning techniques. Learn about Ebbinghaus''s forgetting curve and why testing yourself beats rereading by 2-3 times for long-term retention.</p>', 'Recallify Research Team', '2025-02-10', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1051, 258, 1, 'reading', 'Safe Selection and Handling of Fish and Shellfish', 'https://www.foodsafety.gov/blog/safe-selection-and-handling-fish-and-shellfish', '<p>Learn the essential signs of fresh fish, proper storage temperatures, and safe handling practices to prevent foodborne illness. This official U.S. government guide covers how to identify quality fish at the market and handle it safely at home.</p>', 'FoodSafety.gov', '2023-09-22', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1052, 258, 2, 'reading', 'The Impact of Cooking Methods on the Physical, Sensory, and Nutritional Quality of Fish', 'https://www.sciencedirect.com/science/article/abs/pii/S1878450X2400194X', '<p>An academic review examining how traditional methods (steaming, boiling, frying, smoking) and modern techniques (air frying, sous-vide, microwave) affect fish quality, nutrition, and texture. This provides scientific insight into why different cooking methods work.</p>', 'Malsawmthanga et al.', '2024-11-13', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1053, 258, 3, 'reading', 'How to Fillet a Fish: A Beginner''s Guide', 'https://www.escoffier.edu/blog/recipes/how-to-fillet-a-fish/', '<p>Step-by-step instructions with photos for filleting both round and flat fish, including proper knife techniques, tools needed, and common beginner mistakes to avoid. Perfect for building confidence with fish preparation.</p>', 'Escoffier School of Culinary Arts', '2024-05-08', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4850, 1338, 1, 'reading', 'Getting Started with Claude.ai API: A Guide for Beginners (Part 1 of 6)', 'https://medium.com/@PowerUpSkills/getting-started-with-claude-ai-api-a-guide-for-beginners-part-1-of-6-2288704c07d4', '<p>Comprehensive beginner-friendly introduction to Claude API following Anthropic''s official documentation</p>', 'Jannis', '04/12/2024', 'Blog/Article', NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4851, 1338, 2, 'reading', 'The Rise of Agentic AI: A Review of Definitions, Frameworks, Architectures, Applications, Evaluation Metrics, and Challenges', 'https://www.mdpi.com/1999-5903/17/9/404', '<p>Academic foundation paper covering agentic AI systems, definitions, and architectural frameworks essential for understanding agent-based development</p>', 'Multiple Authors', '04/09/2025', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4852, 1338, 3, 'reading', 'Claude API: How to get a key and use the API', 'https://zapier.com/blog/claude-api/', '<p>Practical step-by-step guide for Claude API setup, authentication, and basic integration patterns</p>', 'Zapier Team', '08/07/2024', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1054, 259, 1, 'reading', 'Confucius', 'https://plato.stanford.edu/entries/confucius/', '<p>Comprehensive introduction to Confucius, his life, and core philosophical ideas from the Stanford Encyclopedia of Philosophy</p>', 'Mark Csikszentmihalyi', '31/03/2020', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (815, 193, 1, 'reading', '3 Traits of an Entrepreneurial Mindset', 'https://mitsloan.mit.edu/ideas-made-to-matter/3-traits-entrepreneurial-mindset', '<p>This accessible article from MIT Sloan introduces the core traits of entrepreneurial thinking: being solutions-oriented, embracing uncertainty, and creating new value. Perfect for understanding what makes entrepreneurs tick.</p>', 'MIT Sloan Global Programs', '2022-11-23', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (816, 193, 2, 'reading', '7 Key Components Every Tech Startup Ecosystem Must Have', 'https://kejoragasbumi.com/how-a-tech-startup-ecosystem-works/', '<p>Learn about the startup ecosystem''s building blocks—from founders and investors to universities and government support. This reading helps you understand the network that supports tech ventures.</p>', 'Kejoragasbumi', '2025-08-24', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (817, 193, 3, 'reading', 'Top 10 Elements of Technology Entrepreneurship', 'https://web.stanford.edu/class/e145/2008_winter/materials/08_winter_slides/TopTenEshipLessons_Byers_Win2008.pdf', '<p>This Stanford resource covers essential topics like cash flow, team building, and the role of context in entrepreneurship. Though created in 2008, the principles remain foundational for understanding tech ventures.</p>', 'Thomas Byers, Stanford University', '2008-01-01', 'Book Chapter', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (818, 193, 4, 'exercise', 'Map Your Entrepreneurial Profile', NULL, NULL, NULL, NULL, NULL, '<p>**Create your personal entrepreneurial assessment:**</p><ol><li><p>Identify 3 characteristics from the readings that you already possess (with specific examples)</p></li><li><p>Choose 2 traits you want to develop and explain why they matter for your goals</p></li><li><p>Research one local startup ecosystem resource (incubator, accelerator, or entrepreneurship center) and write 3-5 sentences about how it could support your journey</p></li><li><p>Reflect: What type of tech business interests you most and why? (2-3 paragraphs)</p></li></ol><p>Submit a 1-2 page document with your responses.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (841, 199, 3, 'reading', 'Mind Mapping for Memory Retention in Nursing Students', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC10852188/', '<p>Explore how mind mapping—a visual note-taking technique—significantly improves both short-term and long-term memory. Learn why organizing information visually helps your brain encode and retrieve information more effectively.</p>', 'Educational Research Team', '2024-02-01', 'Journal Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (842, 199, 4, 'exercise', 'Build Your Memory Toolkit', NULL, NULL, NULL, NULL, NULL, '<p>Create practical tools for applying memory techniques:</p><ol><li><p>**Test Spaced Repetition**: Pick 10 facts/concepts from any subject. Create a simple review schedule: Day 1, Day 3, Day 7, Day 14. Track what you remember.</p></li><li><p>**Practice Active Recall**: Choose a topic you recently learned. Without looking at notes, write/speak everything you remember. Then check and fill gaps.</p></li><li><p>**Create a Mind Map**: Select a complex topic. Draw a colorful mind map with the main idea at center, branches for subtopics, and images/symbols. Compare to your linear notes.</p></li><li><p>**Reflect**: Which technique felt most natural? Which was hardest? Which do you think will stick?</p></li></ol>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1055, 259, 2, 'reading', 'Laozi', 'https://plato.stanford.edu/entries/laozi/', '<p>Scholarly overview of Laozi (Lao Tzu) and Daoist philosophy from the Stanford Encyclopedia</p>', 'Chad Hansen', '15/12/2001', 'Journal Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4853, 1338, 4, 'exercise', 'Build Your First Claude-Powered Development Environment', NULL, NULL, NULL, NULL, NULL, '<p>Create a comprehensive development setup document and basic prototype that demonstrates your understanding of Claude API fundamentals.</p><p>**Your deliverables:**</p><ol><li><p>**Development Environment Documentation**</p></li></ol><ul><li><p>Set up a local development environment with Claude API access</p></li><li><p>Create a detailed setup guide (README.md) that another beginner could follow</p></li><li><p>Include API key management, environment variables, and basic project structure</p></li><li><p>Document at least 3 different ways to interact with Claude (CLI, web interface, API calls)</p></li></ul><ol><li><p>**"Hello Agentic World" Prototype**</p></li></ol><ul><li><p>Build a simple web application that makes API calls to Claude</p></li><li><p>Implement a basic conversational interface where users can ask Claude questions</p></li><li><p>Add a feature that demonstrates Claude''s ability to maintain context across multiple exchanges</p></li><li><p>Include basic error handling and usage monitoring</p></li></ul><ol><li><p>**Reflection Blog Post**</p></li></ol><ul><li><p>Write a 500-word blog post titled "My First Week with Claude API: What I Learned"</p></li><li><p>Share your development setup experience, challenges faced, and solutions found</p></li><li><p>Include cost analysis: track your API usage and estimate monthly costs for different use patterns</p></li><li><p>Publish on a platform like Medium, dev.to, or your personal blog</p></li></ul><p>**Bonus Challenge:** Create a simple agent behavior by having Claude respond differently based on conversation context or user intent patterns.</p><p>**Share your work:** Post your prototype demo video and blog post link in the course community forum for feedback and discussion.</p>', 180) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4854, 1339, 1, 'reading', 'Building Faster with V0 and Claude Code: Lessons Learned from Vibe Coding', 'https://strapi.io/blog/building-faster-with-v0-and-claude-code-lessons-learned-from-vibe-coding', '<p>Practical guide to rapid web development using Claude, covering prompt engineering, architectural patterns, and iterative development workflows for building production-ready applications</p>', 'Strapi Team', '15/01/2025', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4855, 1339, 2, 'reading', 'Agentic AI: A Comprehensive Survey of Architectures, Applications, and Future Directions', 'https://arxiv.org/pdf/2510.25445', '<p>Academic paper establishing dual-paradigm framework for agentic systems, distinguishing symbolic vs neural architectures essential for building web-based agents</p>', 'Mohamad Abou Ali', '29/10/2025', 'Journal Article', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4856, 1339, 3, 'reading', 'Next.js Development Patterns with Claude Code', 'https://developertoolkit.ai/en/cookbook/frontend-recipes/nextjs-patterns/', '<p>Comprehensive patterns for Next.js development with AI assistance, covering App Router, Server Components, and deployment strategies for modern web applications</p>', 'Developer Toolkit', '19/09/2025', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4857, 1339, 4, 'exercise', 'Build Your First Agentic Web Platform', NULL, NULL, NULL, NULL, NULL, '<p>Create a functional web platform that demonstrates agentic AI capabilities using Claude API integration.</p><p>**Core Application Requirements:**</p><ol><li><p>**Multi-Agent Architecture Design**</p></li></ol><ul><li><p>Build a Next.js application with at least 3 distinct "agents" (specialized Claude instances)</p></li><li><p>Agent 1: Content Creator (generates blog posts, articles, or product descriptions)</p></li><li><p>Agent 2: Code Reviewer (analyzes and suggests improvements to user-submitted code)</p></li><li><p>Agent 3: Task Coordinator (manages workflows between agents and user requests)</p></li><li><p>Each agent should have distinct system prompts and capabilities</p></li></ul><ol><li><p>**Agentic Workflow Implementation**</p></li></ol><ul><li><p>Create a task delegation system where users can submit complex requests</p></li><li><p>Implement agent coordination: one agent''s output becomes another''s input</p></li><li><p>Add a "planning agent" that breaks down complex tasks into sub-tasks</p></li><li><p>Include progress tracking and status updates for multi-step workflows</p></li></ul><ol><li><p>**Cost-Conscious Design**</p></li></ol><ul><li><p>Implement token usage tracking and display costs in real-time</p></li><li><p>Add "budget modes" (quick/standard/detailed) that adjust response depth</p></li><li><p>Create agent conversation history that prevents redundant API calls</p></li><li><p>Build a usage analytics dashboard showing cost per agent and per task type</p></li></ul><ol><li><p>**User Experience & Interface**</p></li></ol><ul><li><p>Design a clean dashboard showing active agents and their status</p></li><li><p>Create individual agent interfaces with specialized input forms</p></li><li><p>Add a "agent conversation" view where users can see inter-agent communication</p></li><li><p>Implement real-time updates using WebSockets or Server-Sent Events</p></li></ul><p>**Technical Implementation:**</p><ul><li><p>Use Next.js 15 with App Router and Server Components</p></li><li><p>Implement proper error handling and rate limiting</p></li><li><p>Add database integration (SQLite/PostgreSQL) for conversation persistence</p></li><li><p>Include authentication (NextAuth.js) for user sessions</p></li><li><p>Deploy to Vercel with proper environment variable management</p></li></ul><p>**Deliverables:**</p><ol><li><p>**Working Web Application** - Fully functional platform deployed and accessible online</p></li><li><p>**Architecture Documentation** - Detailed explanation of your agentic system design</p></li><li><p>**Cost Analysis Report** - Breakdown of API costs, optimization strategies, and usage patterns</p></li><li><p>**Demo Video** - 10-minute walkthrough showing agent coordination and real-world use cases</p></li><li><p>**Open Source Repository** - Clean, well-documented code with setup instructions</p></li></ol><p>**Bonus Challenges:**</p><ul><li><p>Add memory persistence so agents remember previous conversations</p></li><li><p>Implement agent specialization learning (agents get better at their specific tasks)</p></li><li><p>Create a "marketplace" where users can create and share custom agent configurations</p></li><li><p>Build mobile-responsive design with PWA capabilities</p></li></ul><p>**Share Your Work:**</p><p>Post your deployed application link, demo video, and repository in the course community. Tag your post with #AgenticWebPlatform and include your cost analysis insights for others to learn from.</p>', 240) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4858, 1340, 1, 'reading', 'Building Effective Agents', 'https://www.anthropic.com/research/building-effective-agents', '<p>Official Anthropic research on agent design principles, covering building blocks, optimization strategies, and production patterns from their engineering team''s experience with customers</p>', 'Anthropic Research Team', '15/10/2024', 'Journal Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1056, 259, 3, 'reading', 'The Art of Chinese Philosophy: Eight Classical Texts and How to Read Them', 'https://www.jstor.org/stable/j.ctvqsdxpx', '<p>Introduction chapter from Goldin''s acclaimed work on reading Chinese philosophical texts - provides essential context for understanding classical Chinese thought</p>', 'Paul R. Goldin', '07/04/2020', 'Book', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4859, 1340, 2, 'reading', 'Claude Agent SDK Tutorial: Create Agents Using Claude Sonnet 4.5', 'https://www.datacamp.com/tutorial/how-to-use-claude-agent-sdk', '<p>Comprehensive tutorial covering the Claude Agent SDK with practical examples, performance optimizations, and integration patterns for building production-ready agents</p>', 'Abid Ali Awan', '29/09/2025', 'Blog/Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4860, 1340, 3, 'reading', 'Optimizing Agentic Coding: How to Use Claude Code in 2026', 'https://research.aimultiple.com/agentic-coding/', '<p>Data-driven analysis of agentic coding optimization patterns, workflow architectures, and performance benchmarks from systematic testing of AI coding tools including Claude Code</p>', 'AIMultiple Research', '15/01/2026', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4861, 1340, 4, 'exercise', 'Deploy & Scale Your Production Agentic Platform', NULL, NULL, NULL, NULL, NULL, '<p>Transform your Week 2 prototype into a production-ready, scalable agentic platform with comprehensive monitoring, cost optimization, and enterprise-grade features.</p><p>**Production Deployment Requirements:**</p><ol><li><p>**Infrastructure & DevOps**</p></li></ol><ul><li><p>Deploy your application using container orchestration (Docker + Kubernetes or similar)</p></li><li><p>Implement CI/CD pipeline with automated testing and deployment</p></li><li><p>Set up production database with proper indexing and connection pooling</p></li><li><p>Configure load balancing and auto-scaling based on agent workload</p></li><li><p>Add comprehensive logging using structured logging (JSON) with correlation IDs</p></li><li><p>Implement health checks and monitoring dashboards (Prometheus/Grafana or similar)</p></li></ul><ol><li><p>**Advanced Agent Optimization**</p></li></ol><ul><li><p>Implement intelligent LLM routing: use cheaper models for simple tasks, Claude for complex ones</p></li><li><p>Add prompt caching to reduce redundant API calls by 30-50%</p></li><li><p>Create agent specialization system where agents learn and improve over time</p></li><li><p>Build context compression techniques to reduce token usage</p></li><li><p>Add conversation memory with vector embeddings for better context retention</p></li><li><p>Implement agent coordination patterns (hierarchical queens/workers or mesh networks)</p></li></ul><ol><li><p>**Enterprise-Grade Features**</p></li></ol><ul><li><p>Add comprehensive authentication and authorization (RBAC)</p></li><li><p>Implement rate limiting and quota management per user/organization</p></li><li><p>Create audit logging for all agent actions and API calls</p></li><li><p>Add data encryption at rest and in transit</p></li><li><p>Build admin dashboard with user management and system analytics</p></li><li><p>Implement backup and disaster recovery procedures</p></li></ul><ol><li><p>**Cost Optimization & Monitoring**</p></li></ol><ul><li><p>Create real-time cost tracking dashboard showing costs per agent, user, and task type</p></li><li><p>Implement budget alerts and automatic throttling when limits are reached</p></li><li><p>Add A/B testing framework to compare different agent configurations</p></li><li><p>Build usage analytics with detailed breakdowns and optimization recommendations</p></li><li><p>Create cost prediction models based on usage patterns</p></li><li><p>Implement intelligent batching to reduce API call overhead</p></li></ul><ol><li><p>**Performance & Reliability**</p></li></ol><ul><li><p>Add comprehensive error handling with graceful degradation</p></li><li><p>Implement retry logic with exponential backoff for API calls</p></li><li><p>Create circuit breakers to handle downstream service failures</p></li><li><p>Add request/response validation and sanitization</p></li><li><p>Implement agent timeout handling and task cancellation</p></li><li><p>Build performance benchmarking and load testing suite</p></li></ul><p>**Technical Architecture Improvements:**</p><ul><li><p>Migrate to microservices architecture with event-driven communication</p></li><li><p>Add message queues (Redis/RabbitMQ) for async agent coordination</p></li><li><p>Implement caching layers (Redis) for frequently accessed data</p></li><li><p>Add API gateway with rate limiting and request routing</p></li><li><p>Create distributed tracing for debugging complex agent workflows</p></li><li><p>Build webhook system for external integrations</p></li></ul><p>**Deliverables:**</p><ol><li><p>**Production Application** - Fully deployed, scalable platform accessible via public URL</p></li><li><p>**Architecture Documentation** - Complete system design with diagrams, API docs, and deployment guides</p></li><li><p>**Performance Analysis Report** - Detailed benchmarks, cost analysis, and optimization results with specific metrics</p></li><li><p>**Operational Runbook** - Monitoring procedures, troubleshooting guides, and maintenance tasks</p></li><li><p>**Demo & Case Study** - 15-minute presentation showing real user scenarios and business impact metrics</p></li><li><p>**Open Source Release** - Production-ready codebase with comprehensive documentation and setup automation</p></li></ol><p>**Advanced Challenges:**</p><ul><li><p>Build agent marketplace where users can create, share, and monetize custom agents</p></li><li><p>Implement federated learning so agents improve from collective usage patterns</p></li><li><p>Add multi-tenant architecture supporting enterprise customers</p></li><li><p>Create agent testing framework with synthetic data generation</p></li><li><p>Build integration APIs for popular business tools (Slack, Notion, GitHub, etc.)</p></li><li><p>Implement real-time collaboration features for multi-user agent sessions</p></li></ul><p>**Business Metrics to Track:**</p><ul><li><p>Daily/Weekly Active Users and retention rates</p></li><li><p>Average cost per user and revenue per customer</p></li><li><p>Agent success rates and user satisfaction scores</p></li><li><p>System uptime and response time percentiles</p></li><li><p>API cost optimization savings and efficiency gains</p></li></ul><p>**Share Your Impact:**</p><p>Create a comprehensive case study blog post documenting your journey from prototype to production. Include specific metrics like cost savings achieved, performance improvements, user adoption rates, and technical lessons learned. Post your case study and production demo link in the course community with the hashtag #ProductionAgenticPlatform.</p><p>**Bonus:** Submit your platform for consideration to relevant startup accelerators, AI showcases, or developer conferences as a real product demo.</p>', 300) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4862, 1341, 1, 'reading', 'Amazon Bedrock AgentCore and Claude: Transforming business with agentic AI', 'https://aws.amazon.com/blogs/machine-learning/amazon-bedrock-agentcore-and-claude-transforming-business-with-agentic-ai/', '<p>Comprehensive analysis of enterprise agentic AI deployments with measurable business outcomes including 63% autonomous issue resolution and 58% faster response times from companies like Cox Automotive and Druva</p>', 'AWS Machine Learning Team', '21/11/2025', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (819, 194, 1, 'reading', 'Why the Lean Start-Up Changes Everything', 'https://hbr.org/2013/05/why-the-lean-start-up-changes-everything', '<p>This Harvard Business Review classic explains how lean startup methodology replaces traditional business planning with experimentation and customer feedback. Essential reading for understanding modern startup validation.</p>', 'Steve Blank', '2013-05-01', 'Journal Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (820, 194, 2, 'reading', 'What is Customer Discovery? A 4-Step Guide', 'https://www.futurefounders.com/news-article/what-is-customer-discovery-4-step-guide-to-building-the-right-product-for-the-right-customers/', '<p>A practical, beginner-friendly guide to customer discovery that breaks down the scientific approach to validating business ideas. Learn why 42% of startups fail due to no market need—and how to avoid that fate.</p>', 'Future Founders', '2021-05-15', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (821, 194, 3, 'reading', 'Towards Continuous Customer Validation: Combining Qualitative Feedback with Quantitative Observation', 'https://www.researchgate.net/publication/283125576_Towards_Continuous_Customer_Validation_A_Conceptual_Model_for_Combining_Qualitative_Customer_Feedback_with_Quantitative_Customer_Observation', '<p>This academic paper from six software companies shows how combining early customer feedback with later observation creates better products. It''s more technical but provides research-backed validation methods.</p>', 'Helena Holmström Olsson and Jan Bosch', '2015-06-10', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (822, 194, 4, 'exercise', 'Conduct Mini Customer Discovery Interviews', NULL, NULL, NULL, NULL, NULL, '<p>**Practice the customer discovery process:**</p><ol><li><p>**Choose a problem**: Identify a challenge you or people you know face regularly (related to technology, daily life, or work)</p></li><li><p>**Create 5-7 interview questions** to understand the problem (avoid leading questions like "Would you buy...?")</p></li><li><p>**Interview 3 people** who might experience this problem (friends, family, classmates)</p></li><li><p>**Document your findings**: What did you learn? Were your assumptions correct? What surprised you?</p></li><li><p>**Synthesize insights**: Write 2-3 paragraphs on whether this problem is worth solving and why</p></li></ol><p>Submit your interview questions, notes from conversations, and final reflection.</p>', 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (843, 200, 1, 'reading', 'The First 20 Hours: How to Learn Anything', 'https://www.youtube.com/watch?v=5MgBikgcWnY', '<p>Watch Josh Kaufman''s famous TEDx talk on rapid skill acquisition. He demonstrates how breaking down complex skills and practicing deliberately for just 20 hours can take you from knowing nothing to performing noticeably well.</p>', 'Josh Kaufman', '2013-03-14', 'Youtube video', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4863, 1341, 2, 'reading', 'Claude in the enterprise: case studies of AI deployments and real-world results', 'https://www.datastudios.org/post/claude-in-the-enterprise-case-studies-of-ai-deployments-and-real-world-results-1', '<p>In-depth case studies from Bridgewater Associates, Newfront, Zapier, and Tines showing practical enterprise implementations, integration patterns, and quantified business impact across financial services, insurance, and cybersecurity sectors</p>', 'Data Studios Research', '02/09/2025', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4864, 1341, 3, 'reading', 'How I Built A Production-Quality Enterprise API With Claude Code In 7 Days — My Vibysitting Adventure', 'https://mikesparr.medium.com/how-i-built-a-production-quality-enterprise-api-with-claude-code-in-7-days-my-vibysitting-21b1337d8504', '<p>Real-world engineering case study detailing practical techniques for building production-grade enterprise APIs using Claude Code with specific architectural patterns, security implementations, and development workflows</p>', 'Mike Sparr', '09/10/2025', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (4865, 1341, 4, 'exercise', 'Launch Your Agentic Platform as a Real Business', NULL, NULL, NULL, NULL, NULL, '<p>Transform your Week 3 production platform into a viable business by creating a comprehensive go-to-market strategy, implementing enterprise features, and launching to real customers.</p><p>**Business Development & Strategy:**</p><ol><li><p>**Market Research & Business Model Design**</p></li></ol><ul><li><p>Conduct 20+ customer interviews with potential enterprise users</p></li><li><p>Analyze 5 direct competitors and identify differentiation opportunities</p></li><li><p>Create detailed customer personas and value proposition canvas</p></li><li><p>Design pricing strategy with at least 3 tiers (Starter, Professional, Enterprise)</p></li><li><p>Build financial projections including customer acquisition costs and lifetime value</p></li><li><p>Create business model canvas and pitch deck for potential investors/partners</p></li></ul><ol><li><p>**Enterprise-Grade Product Development**</p></li></ol><ul><li><p>Implement multi-tenancy with organization-level isolation and billing</p></li><li><p>Add comprehensive admin dashboard with user management, usage analytics, and billing integration</p></li><li><p>Build enterprise authentication (SSO, SAML, Active Directory integration)</p></li><li><p>Create white-label capabilities for enterprise customers</p></li><li><p>Implement advanced security features (data encryption, audit logs, compliance reporting)</p></li><li><p>Add webhook system and REST/GraphQL APIs for customer integrations</p></li><li><p>Build mobile app or PWA for on-the-go access</p></li></ul><ol><li><p>**Go-to-Market Execution**</p></li></ol><ul><li><p>Launch landing page with conversion optimization and A/B testing</p></li><li><p>Create comprehensive product documentation and developer guides</p></li><li><p>Build onboarding flow with in-app tutorials and success metrics tracking</p></li><li><p>Implement customer support system (knowledge base, ticketing, live chat)</p></li><li><p>Design referral program and customer success workflows</p></li><li><p>Create content marketing strategy with case studies, tutorials, and thought leadership</p></li><li><p>Launch on Product Hunt and relevant startup/AI communities</p></li></ul><ol><li><p>**Customer Acquisition & Validation**</p></li></ol><ul><li><p>Acquire at least 10 paying customers across different use cases</p></li><li><p>Implement customer feedback loop with regular surveys and feature request tracking</p></li><li><p>Create customer advisory board with 3-5 strategic users</p></li><li><p>Build case studies showcasing measurable business impact</p></li><li><p>Establish partnerships with complementary SaaS tools or consultants</p></li><li><p>Launch affiliate program targeting AI/productivity influencers</p></li><li><p>Create enterprise sales process with demo environment and trial programs</p></li></ul><p>**Technical & Operational Excellence:**</p><ol><li><p>**Advanced Platform Features**</p></li></ol><ul><li><p>Add marketplace for community-created agents and workflows</p></li><li><p>Implement agent collaboration features (shared workspaces, handoffs, coordination)</p></li><li><p>Build analytics dashboard showing ROI, productivity gains, and usage patterns</p></li><li><p>Create agent performance benchmarking and optimization recommendations</p></li><li><p>Add integration marketplace (Slack, Microsoft Teams, Notion, Salesforce, etc.)</p></li><li><p>Implement advanced prompt management and version control for enterprise customers</p></li><li><p>Build compliance features for GDPR, SOC2, HIPAA requirements</p></li></ul><ol><li><p>**Business Operations & Scale**</p></li></ol><ul><li><p>Implement comprehensive business metrics tracking (MRR, churn, CAC, LTV)</p></li><li><p>Set up customer success automation and health scoring</p></li><li><p>Build automated billing and subscription management</p></li><li><p>Create operational runbooks for scaling customer support</p></li><li><p>Implement feature flags and gradual rollout capabilities</p></li><li><p>Design disaster recovery and business continuity plans</p></li><li><p>Establish legal framework (terms of service, privacy policy, data processing agreements)</p></li></ul><p>**Advanced Challenges & Innovation:**</p><ul><li><p>Build AI-powered customer success agent that proactively identifies at-risk accounts</p></li><li><p>Create federated learning system where customer agents improve from collective usage</p></li><li><p>Implement edge computing deployment for customers with data residency requirements</p></li><li><p>Build agent marketplace with revenue sharing for community contributors</p></li><li><p>Create enterprise consulting services for custom agent development</p></li><li><p>Launch API platform allowing third-party developers to build on your infrastructure</p></li></ul><p>**Deliverables & Milestones:**</p><p>**Week 1-2: Business Foundation**</p><ol><li><p>**Business Plan & Strategy Document** - Complete business model, market analysis, financial projections</p></li><li><p>**Customer Interview Report** - Insights from 20+ potential customer conversations</p></li><li><p>**Competitive Analysis** - Detailed comparison with key players and differentiation strategy</p></li><li><p>**Brand Identity & Marketing Materials** - Logo, website, pitch deck, sales collateral</p></li></ol><p>**Week 3-4: Product & Launch**</p><ol><li><p>**Enterprise-Ready Platform** - Multi-tenant, secure, scalable application with enterprise features</p></li><li><p>**Go-to-Market Campaign** - Content marketing, Product Hunt launch, outreach campaigns</p></li><li><p>**Customer Acquisition Results** - At least 10 paying customers with documented success stories</p></li><li><p>**Operational Systems** - Support, billing, analytics, and customer success infrastructure</p></li></ol><p>**Week 5-8: Growth & Scale**</p><ol><li><p>**Case Study Collection** - Document quantified business impact from customer deployments</p></li><li><p>**Partnership Agreements** - Establish relationships with at least 2 strategic partners</p></li><li><p>**Revenue Milestone** - Achieve minimum viable revenue target ($10k+ MRR)</p></li><li><p>**Investment Preparation** - Due diligence package ready for seed funding discussions</p></li></ol><p>**Success Metrics to Track:**</p><ul><li><p>**Customer Metrics:** Monthly Recurring Revenue (MRR), Customer Acquisition Cost (CAC), Customer Lifetime Value (LTV), Net Revenue Retention, Churn Rate</p></li><li><p>**Product Metrics:** Daily/Monthly Active Users, Feature Adoption Rates, Customer Health Scores, Support Ticket Resolution Time</p></li><li><p>**Business Metrics:** Gross Margin, Runway Remaining, Revenue Growth Rate, Market Share in Target Segments</p></li></ul><p>**Final Presentation Requirements:**</p><p>Create a 20-minute investor-style presentation covering:</p><ul><li><p>Problem/Solution Fit with customer validation</p></li><li><p>Product Demo showcasing enterprise capabilities</p></li><li><p>Business Model and Unit Economics</p></li><li><p>Market Opportunity and Competitive Landscape</p></li><li><p>Customer Traction and Case Studies</p></li><li><p>Technology Differentiation and IP Strategy</p></li><li><p>Team Capabilities and Advisory Board</p></li><li><p>Financial Projections and Funding Requirements</p></li><li><p>Roadmap and Growth Strategy</p></li></ul><p>**Community Impact & Sharing:**</p><p>Document your entire journey as an open-source case study:</p><ul><li><p>Weekly progress blog posts with metrics and lessons learned</p></li><li><p>Open-source the non-proprietary components of your platform</p></li><li><p>Create educational content teaching others how to build similar businesses</p></li><li><p>Speak at conferences or meetups about agentic AI entrepreneurship</p></li><li><p>Mentor other developers looking to commercialize their AI projects</p></li></ul><p>**Ultimate Challenge:**</p><p>By the end of this exercise, your goal is to have a real, revenue-generating business that could qualify for Y Combinator, Techstars, or similar accelerator programs. Treat this as building an actual startup, not just a learning exercise.</p><p>**Share Your Success:**</p><p>Post your business metrics, customer testimonials, and product demo in the course community with hashtag #AgenticBusinessLaunch. Include your pitch deck and be prepared to answer questions from other entrepreneurs in the program.</p>', 480) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (844, 200, 2, 'reading', 'Skill Deconstruction and Accelerated Learning Strategies', 'https://first20hours.com/', '<p>Explore Kaufman''s systematic approach to deconstructing complex skills, maximizing productive practice, and removing learning barriers. This resource provides the 10 principles of rapid skill acquisition and practical examples.</p>', 'Josh Kaufman', '2013-06-13', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (845, 200, 3, 'reading', 'Skill Acquisition is Enhanced by Reducing Trial-to-Trial Repetition', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC7191519/', '<p>Read this neuroscience research on how practice structure affects learning. The study shows that minimizing consecutive repetition leads to greater long-term skill acquisition—key insights for designing your practice sessions.</p>', 'R. M. Hardwick et al.', '2020-05-01', 'Journal Article', NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (846, 200, 4, 'exercise', 'Design Your 20-Hour Skill Acquisition Plan', NULL, NULL, NULL, NULL, NULL, '<p>Choose one specific skill you want to acquire and create a complete learning plan:</p><ol><li><p>**Deconstruct**: Break the skill into 5-7 sub-skills or components</p></li><li><p>**Prioritize**: Identify the 2-3 most critical sub-skills to practice first</p></li><li><p>**Remove Barriers**: List 3 obstacles to practice and how you''ll eliminate them</p></li><li><p>**Create Schedule**: Design a 20-hour practice plan (e.g., 45 min/day for 4 weeks)</p></li><li><p>**Define Success**: Describe what "good enough" performance looks like</p></li></ol><p>Document your plan in a format you can actually use. Be specific about what you''ll practice and when.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1057, 259, 4, 'exercise', 'Create a Philosophy Dialogue Video', NULL, NULL, NULL, NULL, NULL, '<p>Create a 5-7 minute video dialogue between Confucius and Laozi discussing their different approaches to living a good life.</p><p>**Your mission:**</p><ol><li><p>**Write the script** - Create a natural conversation that showcases their key differences:</p></li></ol><ul><li><p>Confucius: Focus on social harmony, ritual (li), virtue (de), education</p></li><li><p>Laozi: Emphasis on naturalness, wu wei (non-action), simplicity, spontaneity</p></li><li><p>Include 2-3 specific disagreements and how they might find common ground</p></li></ul><ol><li><p>**Choose your format:**</p></li></ol><ul><li><p>Animated video using simple tools like Powtoon or Canva</p></li><li><p>Live-action with friends/family as the philosophers</p></li><li><p>Puppet show or creative visual storytelling</p></li><li><p>Audio drama with visuals</p></li></ul><ol><li><p>**Make it accessible** - Explain complex concepts in everyday language that a general audience can understand</p></li></ol><ol><li><p>**Share your creation** - Upload to YouTube, TikTok, or another platform and share the link in a philosophy discussion forum or social media group</p></li></ol><p>**Bonus challenge:** Include a brief (1-2 minute) reflection at the end sharing which philosopher''s approach resonates more with your own life and why.</p>', 180) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1058, 260, 1, 'reading', 'Mencius (Mengzi)', 'https://iep.utm.edu/mencius/', '<p>Comprehensive overview of Mencius''s philosophy, including his famous argument that human nature is inherently good and his four ''sprouts'' theory</p>', 'Curie Virág', '15/01/2006', 'Journal Article', NULL, 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1059, 260, 2, 'reading', 'Xunzi (Hsün Tzu)', 'https://iep.utm.edu/xunzi/', '<p>Detailed examination of Xunzi''s counter-argument that human nature is evil and requires ritual transformation to achieve goodness</p>', 'T.C. Kline III and Justin Tiwald', '12/04/2005', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1060, 260, 3, 'reading', 'Beyond Respecting Mencius and Criticizing Xunzi: A Return to Equal Status for the Two Sages', 'https://brill.com/view/journals/joch/6/1/article-p43_4.xml?language=en', '<p>Scholarly analysis of how both philosophers'' theories can be reconciled within Confucian thought, emphasizing their complementary rather than contradictory nature</p>', 'Tao Liang', '09/12/2020', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1061, 260, 4, 'exercise', 'Design a Moral Education Program', NULL, NULL, NULL, NULL, NULL, '<p>Drawing on the Mencius vs. Xunzi debate, design a practical moral education program for a real institution (school, company, community center, etc.).</p><p>**Your challenge:**</p><ol><li><p>**Choose your context:**</p></li></ol><ul><li><p>Elementary/middle/high school character education</p></li><li><p>Corporate ethics training program</p></li><li><p>Community youth development</p></li><li><p>Prison rehabilitation program</p></li><li><p>Other institution of your choice</p></li></ul><ol><li><p>**Take a philosophical stance:**</p></li></ol><ul><li><p>**Mencian approach:** Assume people are naturally good - focus on nurturing innate moral instincts, creating supportive environments, encouraging self-reflection</p></li><li><p>**Xunzian approach:** Assume people need external structure - emphasize rules, rituals, social norms, clear consequences</p></li><li><p>**Hybrid approach:** Combine both theories strategically</p></li></ul><ol><li><p>**Create your program:**</p></li></ol><ul><li><p>Write a 2-3 page program proposal including:</p></li><li><p>Target audience and institutional context</p></li><li><p>Philosophical foundation (why your approach fits)</p></li><li><p>5-7 specific activities/methods</p></li><li><p>Assessment/evaluation strategy</p></li><li><p>Timeline and resource requirements</p></li></ul><ol><li><p>**Pilot test your ideas:**</p></li></ol><ul><li><p>Identify someone in your chosen institution (teacher, manager, community leader)</p></li><li><p>Present your proposal and gather feedback</p></li><li><p>Document their reactions and suggestions</p></li></ul><ol><li><p>**Share your work:**</p></li></ol><ul><li><p>Post your proposal on LinkedIn, Medium, or educational forums</p></li><li><p>Tag relevant professionals in your field</p></li><li><p>Include reflection on which philosopher''s insights proved most practical</p></li></ul><p>**Bonus:** If possible, implement one small component of your program and document the results.</p>', 240) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1062, 261, 1, 'reading', 'Zhuangzi', 'https://plato.stanford.edu/entries/zhuangzi/', '<p>Comprehensive overview of Zhuangzi as the pivotal figure in philosophical Daoism, exploring his skepticism, relativism, and critique of conventional thinking</p>', 'Chad Hansen', '17/12/2014', 'Journal Article', NULL, 50) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1063, 261, 2, 'reading', 'Freedom and agency in the Zhuangzi: navigating life''s constraints', 'https://www.tandfonline.com/doi/full/10.1080/09608788.2021.1994366', '<p>Modern scholarly analysis of how Zhuangzi''s philosophy offers practical guidance for living freely within life''s constraints and social expectations</p>', 'Karyn Lai', '15/11/2021', 'Journal Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1064, 261, 3, 'reading', 'Legalism in Chinese Philosophy', 'https://plato.stanford.edu/entries/chinese-legalism/', '<p>Detailed examination of Chinese Legalism, focusing on Han Feizi''s political philosophy and its emphasis on law, administrative techniques, and state power</p>', 'Yuri Pines', '10/12/2014', 'Journal Article', NULL, 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1065, 261, 4, 'exercise', 'Host a Philosophy Café Debate', NULL, NULL, NULL, NULL, NULL, '<p>Organize and moderate a public philosophy discussion between supporters of Zhuangzi''s approach vs. Legalist governance.</p><p>**Your mission:**</p><ol><li><p>**Find your venue:**</p></li></ol><ul><li><p>Local café, library, community center, or bookstore</p></li><li><p>University campus space or coworking area</p></li><li><p>Online via Zoom, Discord, or Clubhouse</p></li><li><p>Your own living room with friends/neighbors</p></li></ul><ol><li><p>**Design the debate format:**</p></li></ol><ul><li><p>**The scenario:** A community is facing a crisis (choose one):</p></li><li><p>Environmental disaster requiring immediate coordinated action</p></li><li><p>Economic inequality and social unrest</p></li><li><p>Public health emergency</p></li><li><p>Educational system reform</p></li><li><p>**Zhuangzi team argues:** Natural solutions, minimal intervention, trust in organic social responses, skepticism of rigid rules</p></li><li><p>**Legalist team argues:** Clear laws, strong leadership, systematic enforcement, practical results over ideals</p></li></ul><ol><li><p>**Prepare materials:**</p></li></ol><ul><li><p>Create 1-page handouts summarizing each philosophy</p></li><li><p>Write 5-7 specific debate questions</p></li><li><p>Prepare opening scenarios and closing reflection prompts</p></li><li><p>Design simple name tags: "Team Zhuangzi" vs "Team Han Feizi"</p></li></ul><ol><li><p>**Facilitate the event:**</p></li></ol><ul><li><p>Aim for 90 minutes: intro (15 min) + debate (60 min) + reflection (15 min)</p></li><li><p>Recruit 6-12 participants (friends, colleagues, community members)</p></li><li><p>Randomly assign teams regardless of personal beliefs</p></li><li><p>Keep discussion respectful and philosophical, not partisan</p></li></ul><ol><li><p>**Document and share:**</p></li></ol><ul><li><p>Record key insights and surprising moments</p></li><li><p>Ask participants to share their biggest takeaway</p></li><li><p>Write a 500-word reflection on what you learned about both philosophies in practice</p></li><li><p>Post about the experience on social media or a blog</p></li><li><p>Share your format/materials with other philosophy enthusiasts online</p></li></ul><p>**Bonus challenges:**</p><ul><li><p>Partner with a local philosophy meetup or book club</p></li><li><p>Invite a philosophy professor to observe and provide expert commentary</p></li><li><p>Plan a follow-up event exploring a different philosophical dilemma</p></li></ul>', 300) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1066, 262, 1, 'reading', 'Neo-Confucianism', 'https://plato.stanford.edu/entries/neo-confucianism/', '<p>Comprehensive overview of Neo-Confucianism''s synthesis of Confucian, Daoist, and Buddhist elements, focusing on key figures like Zhu Xi and Wang Yangming</p>', 'JeeLoo Liu', '15/06/2006', 'Journal Article', NULL, 55) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1067, 262, 2, 'reading', 'Chinese Philosophy and Contemporary Ethics', 'https://www.cambridge.org/core/journals/journal-of-value-inquiry/article/chinese-philosophy-and-contemporary-ethics/8B4A5C2E3F8B9D1A6E2C4F7A9B5E8D3C', '<p>Analysis of how classical Chinese philosophical concepts like harmony, reciprocity, and role-based ethics offer insights for contemporary moral challenges</p>', 'Ames, Roger T.', '12/03/2019', 'Journal Article', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1068, 262, 3, 'reading', 'The Relevance of Confucianism to Contemporary Business Ethics', 'https://link.springer.com/article/10.1007/s10551-018-3772-4', '<p>Exploration of how Confucian values of benevolence, righteousness, and social responsibility apply to modern business practices and corporate culture</p>', 'Xiaoping Du and Christine Tang', '25/01/2018', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1069, 262, 4, 'exercise', 'Launch a ''Practical Philosophy'' Initiative', NULL, NULL, NULL, NULL, NULL, '<p>Create and launch a real project that brings Chinese philosophical wisdom to address a contemporary challenge in your community or field.</p><p>**Your capstone project:**</p><ol><li><p>**Identify your focus area:**</p></li></ol><ul><li><p>Workplace culture and leadership</p></li><li><p>Environmental sustainability practices</p></li><li><p>Community mental health and wellbeing</p></li><li><p>Educational reform and student development</p></li><li><p>Technology ethics and digital wellness</p></li><li><p>Social justice and community organizing</p></li><li><p>Other area where you have expertise/passion</p></li></ul><ol><li><p>**Choose your philosophical framework:**</p></li></ol><ul><li><p>**Confucian approach:** Emphasize relationships, moral cultivation, social harmony, education</p></li><li><p>**Daoist principles:** Natural flow, balance, simplicity, wu wei (effortless action)</p></li><li><p>**Neo-Confucian synthesis:** Integration of personal development with social responsibility</p></li><li><p>**Multi-school approach:** Draw strategically from different traditions</p></li></ul><ol><li><p>**Design your initiative:**</p></li></ol><ul><li><p>**Workshop series:** 4-6 sessions teaching philosophical concepts through practical exercises</p></li><li><p>**Mentorship program:** Pair classical wisdom with modern challenges</p></li><li><p>**Community action project:** Organize collective efforts inspired by Chinese philosophy</p></li><li><p>**Digital platform:** App, newsletter, or social media campaign sharing daily wisdom</p></li><li><p>**Book club or discussion group:** Regular meetings exploring philosophical texts and applications</p></li></ul><ol><li><p>**Create supporting materials:**</p></li></ol><ul><li><p>Write a clear mission statement connecting philosophy to practice</p></li><li><p>Develop 3-5 core resources (handouts, videos, templates, guides)</p></li><li><p>Build partnerships with relevant organizations or influencers</p></li><li><p>Design simple branding and promotional materials</p></li></ul><ol><li><p>**Launch and document:**</p></li></ol><ul><li><p>Execute your initiative with at least 10 participants</p></li><li><p>Collect feedback through surveys or interviews</p></li><li><p>Document success stories and unexpected insights</p></li><li><p>Measure impact using specific metrics (engagement, behavior change, etc.)</p></li><li><p>Create a final report or case study</p></li></ul><ol><li><p>**Scale and share:**</p></li></ol><ul><li><p>Present your results at a conference, meetup, or online forum</p></li><li><p>Write an article for Medium, LinkedIn, or relevant publication</p></li><li><p>Open-source your materials for others to adapt</p></li><li><p>Plan next steps for growth or replication</p></li></ul><p>**Deliverables:**</p><ul><li><p>Launch announcement (social media, email, website)</p></li><li><p>3-5 supporting materials or resources</p></li><li><p>Documentation of at least one full cycle/session</p></li><li><p>Final reflection paper (1000-1500 words) on insights gained</p></li><li><p>Public sharing of results and materials</p></li></ul><p>**Success metrics:**</p><ul><li><p>Real engagement from your target audience</p></li><li><p>Concrete examples of philosophical insights leading to practical changes</p></li><li><p>Positive feedback and requests for continuation</p></li><li><p>Personal growth in understanding Chinese philosophy''s relevance</p></li></ul>', 480) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1070, 263, 1, 'reading', 'The Constitution of the United States', 'https://www.archives.gov/founding-docs/constitution-transcript', 'The primary source document. Read the Preamble and Articles I-III establishing the three branches.', 'National Archives', '1787-01-01', 'Blog/Article', NULL, 45) ON CONFLICT DO NOTHING;
