INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1081, 264, 5, 'reading', 'Checks and Balances', 'https://en.wikipedia.org/wiki/Checks_and_balances', 'Detailed explanation of how each branch can limit the powers of the others.', 'Wikipedia', '2025-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
