INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1083, 264, 7, 'exercise', 'Track a Bill', NULL, 'Go to Congress.gov and find a bill currently in Congress on a topic you care about.', NULL, NULL, NULL, 'Document what the bill proposes and current status and key sponsors and arguments for and against. Write a 300-word summary.', 45) ON CONFLICT DO NOTHING;
