INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1085, 265, 2, 'reading', 'Crash Course Government #11: Presidential Power (YouTube)', 'https://www.youtube.com/watch?v=5l02sK5LovI', 'Examines the expressed powers of the President in the Constitution from appointing judges to vetoing laws to foreign policy.', 'Crash Course (Craig Benzine)', '2015-01-01', 'YouTube Video', NULL, 7) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1086, 265, 3, 'reading', 'Civil Liberties and Civil Rights', 'https://en.wikipedia.org/wiki/Civil_liberties_in_the_United_States', 'Understanding the difference between civil liberties (freedoms from government) and civil rights (equality guarantees).', 'Wikipedia', '2025-01-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
