INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5415, 2062, 1, 'reading', 'On Writing Well', 'https://example.com/on-writing-well', NULL, NULL, NULL, NULL, NULL, 30) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1220, 298, 1, 'reading', 'A Hidden History of Film Style', 'https://www.amazon.com/Hidden-History-Film-Style-Cinematographers/dp/0520284356', '<p><cite index=''4-1,4-18,4-23,4-24,4-25''>A groundbreaking study exploring the collaborative nature of filmmaking, challenging the auteur theory by highlighting the crucial partnership between directors and cinematographers in American cinema</cite></p>', 'Christopher Beach', '15/10/2015', 'Book', NULL, 120) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1221, 298, 2, 'reading', 'The History of Cinema: A Very Short Introduction', 'https://www.amazon.com/History-Cinema-Short-Introduction-Introductions/dp/0198701772', '<p><cite index=''9-2,9-4,9-5,9-6''>Explores cinema as a transformative art form that developed against the backdrop of world wars, reflecting technological and social changes through its evolution from silent to sound, black and white to color</cite></p>', 'Geoffrey Nowell-Smith', '01/01/2017', 'Book', NULL, 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1222, 298, 3, 'reading', 'The Oxford History of World Cinema', 'https://www.worldcat.org/title/oxford-history-of-world-cinema/oclc/35160641', '<p><cite index=''5-15,5-16,5-17,5-18''>A comprehensive chronicle of cinema''s global development, tracing its rise from a novelty to a global art form that spans diverse traditions beyond Hollywood</cite></p>', 'Geoffrey Nowell-Smith (Editor)', '01/01/1996', 'Book', NULL, 180) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1223, 298, 4, 'exercise', 'Cinematographic Time Capsule Project', NULL, NULL, NULL, NULL, NULL, '<p>Create a multimedia presentation that captures the spirit of early 20th-century cinematography:</p><ol><li><p>Research and select ONE pioneering cinematographer from the early 1900s (before 1930)</p></li><li><p>Design a 5-10 minute digital documentary or video essay that includes:</p></li></ol><ul><li><p>Brief biographical overview</p></li><li><p>2-3 of their most innovative cinematographic techniques</p></li><li><p>Historical context of their work</p></li><li><p>At least one visual recreation or analysis of their signature style</p></li></ul><ol><li><p>Choose your presentation format:</p></li></ol><ul><li><p>Video documentary</p></li><li><p>Podcast episode</p></li><li><p>Interactive web presentation</p></li><li><p>Illustrated long-form article</p></li></ul><ol><li><p>Publish your work on a public platform (YouTube, Vimeo, Medium, personal blog) and share the link in a film studies community or forum</p></li></ol><p>Bonus challenges:</p><ul><li><p>Include period-appropriate visual or audio elements</p></li><li><p>Interview a film historian or cinematography expert (even via email)</p></li><li><p>Demonstrate how this early cinematographer influenced modern filmmaking</p></li></ul>', 360) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1224, 299, 1, 'reading', 'Widescreen and Color: Revolutionizing the Cinema Experience', 'https://www.jstor.org/stable/j.ctt1xhr4j7', '<p><cite index=''2-1:4''>Details the emergence of innovative film technologies like CinemaScope, which transformed image projection, and the introduction of stereo sound in the 1950s</cite></p>', 'Martin Scorsese', '15/03/2010', 'Book Chapter', NULL, 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1225, 299, 2, 'reading', 'Masters of Light: Cinematography in the Golden Age of Hollywood', 'https://www.worldcat.org/title/masters-of-light-conversations-with-contemporary-cinematographers/oclc/13606462', '<p><cite index=''9-1,9-2:6''>Explores landmark cinematographic achievements like Gregg Toland''s revolutionary deep-focus techniques in Citizen Kane and Freddie Young''s epic cinematography in Lawrence of Arabia</cite></p>', 'Dennis Schaefer', '01/06/1984', 'Book', NULL, 120) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1226, 299, 3, 'reading', 'Journal of Film and Video: Cinematographic Innovations', 'https://www.jstor.org/journal/jfilmvideo', '<p><cite index=''7-1,7-2''>Examines the rapid innovations in early-to-mid 20th century filmmaking, including editing techniques, special effects, close-ups, sound, widescreen, and color films</cite></p>', 'American Film Institute', '15/09/1995', 'Journal Article', NULL, 60) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1227, 299, 4, 'exercise', 'Cinematic Time Machine: Reconstructing Mid-Century Visual Storytelling', NULL, NULL, NULL, NULL, NULL, '<p>Create a comprehensive multimedia project that reimagines a mid-20th century film scene using period-accurate cinematographic techniques:</p><ol><li><p>Research Selection:</p></li></ol><ul><li><p>Choose ONE iconic film from 1940-1960</p></li><li><p>Study its specific cinematographic innovations</p></li></ul><ol><li><p>Technical Reconstruction:</p></li></ol><ul><li><p>Recreate a 3-5 minute scene using:</p></li><li><p>Period-appropriate camera techniques</p></li><li><p>Lens choices matching the era</p></li><li><p>Lighting styles characteristic of the time</p></li><li><p>Color or black-and-white aesthetic</p></li></ul><ol><li><p>Documentation:</p></li></ol><ul><li><p>Produce a 10-15 minute video essay explaining:</p></li><li><p>Historical context of the original film</p></li><li><p>Specific cinematographic techniques used</p></li><li><p>Your process of technical recreation</p></li><li><p>Challenges in capturing the era''s visual language</p></li></ul><ol><li><p>Presentation Options:</p></li></ol><ul><li><p>Film school workshop</p></li><li><p>Online film studies forum</p></li><li><p>YouTube film analysis channel</p></li><li><p>Local cinematography meetup</p></li></ul><p>Bonus Challenges:</p><ul><li><p>Use vintage or vintage-style equipment</p></li><li><p>Collaborate with a local film historian</p></li><li><p>Include a comparative analysis with modern techniques</p></li></ul>', NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1228, 299, 5, 'reading', 'Filmmaker IQ: Digital Cinematography Evolution', 'https://www.youtube.com/c/FilmmakerIQ', '<p><cite index=''8-1''>Filmmaker IQ provides comprehensive filmmaking tutorials that rival many college courses in their detail</cite>. <cite index=''9-1,9-2''>The channel helps filmmakers learn fundamentals, including how lights work and reflect emotions in a scene</cite>.</p>', 'John P. Hess', '15/03/2024', 'Video', '<p>Watch the video and reflect on how digital technologies transformed cinematography in the late 20th and early 21st centuries. Consider the technical and artistic implications of the shift from film to digital mediums.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1229, 300, 1, 'reading', 'Digital Cinematography: Reimagining the Moving Image', 'https://www.worldcat.org/title/new-media-reader/oclc/50730170', '<p><cite index=''10-1,10-6:13''>Explores how digital technologies have fundamentally transformed cinema, shifting from a medium of capturing reality to a more malleable form of visual expression, breaking down traditional boundaries of filmmaking</cite></p>', 'Lev Manovich', '15/09/2003', 'Book Chapter', NULL, 120) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1230, 300, 2, 'reading', 'The Digital Image: Cinema and Beyond', 'https://www.jstor.org/stable/j.ctt1xhr4j7', '<p><cite index=''1-2,1-9:11,5-1,5-16:18''>Examines the digital revolution''s impact on filmmaking, highlighting how digital cameras, CGI, and new distribution platforms have democratized film production and transformed audience experiences</cite></p>', 'David Bordwell', '01/06/2012', 'Journal Article', NULL, 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1089, 265, 6, 'exercise', 'Rights in Action', NULL, 'Take the official USCIS naturalization civics practice test.', NULL, NULL, NULL, 'Then choose one right from the Bill of Rights and find a recent news story where it was invoked. Analyze how the right was applied.', 45) ON CONFLICT DO NOTHING;
