INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1091, 266, 2, 'reading', 'We the People: The Citizen and the Constitution (Chapter on Civic Participation)', 'https://www.civiced.org/resources/curriculum/we-the-people', 'Center for Civic Education curriculum on how citizens can participate in democracy. Focuses on the importance and methods of civic engagement.', 'Center for Civic Education', '2024-01-01', 'Book Chapter', NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1092, 266, 3, 'reading', 'How to Inspire Civic Action', 'https://www.escribemeetings.com/blog/civic-action/', 'Step-by-step guide to community organizing and advocacy and creating change at the local level.', 'eScribe', '2024-08-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1093, 266, 4, 'reading', 'Civic Engagement Examples: 8 Ways to Get Involved', 'https://www.change.org/l/us/civic-engagement-examples', 'Practical examples from petitions to local boards to fundraising for causes you care about.', 'Change.org', '2024-01-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1094, 266, 5, 'reading', 'Community Organizing and Grassroots Movements for Change', 'https://www.insidehighered.com/opinion/columns/higher-ed-gamma/2025/02/28/community-organizing-and-grassroots-movements-change', 'How ordinary citizens have driven major social transformations through collective action.', 'Inside Higher Ed', '2025-02-01', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1095, 266, 6, 'reading', 'The Power of Grassroots Movements in Political Change', 'https://goodparty.org/blog/article/grassroots-movement', 'Explains how grassroots organizing builds democracy through citizen engagement and accountability.', 'GoodParty.org', '2023-05-01', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1096, 266, 7, 'reading', 'Civic Nation', 'https://civicnation.org/', 'Explore programs like When We All Vote and All In Campus Democracy Challenge for practical civic engagement.', 'Civic Nation', '2024-01-01', 'Blog/Article', NULL, 15) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1097, 266, 8, 'exercise', 'Create Your Civic Action Plan', NULL, 'Identify an issue in your community you want to address.', NULL, NULL, NULL, 'Create a 4-week action plan with research and stakeholders and 3 concrete actions and success metrics. Begin implementing at least one action this week.', 90) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5416, 2062, 2, 'exercise', 'Write a 500-word memoir', NULL, NULL, NULL, NULL, NULL, 'Write a 500-word memoir about a formative childhood experience.', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (935, 223, 1, 'reading', 'Posthog Official Documentation: Install and Getting Started Guide', 'https://github.com/PostHog/posthog.com/blob/master/contents/tutorials/event-tracking-guide.md', '<p>Start here to learn how to install Posthog and set up both autocapture and custom event tracking. This official tutorial walks through the core setup process step-by-step.</p>', 'PostHog Team', '2024-01-15', 'Blog/Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (936, 223, 2, 'reading', 'Tracking Web and Product Analytics with PostHog in Flask', 'https://blog.teclado.com/analytics-posthog-python-flask/', '<p>A practical guide that demonstrates how to integrate Posthog into web applications, covering user identification, event tracking, and dashboard navigation. Great for understanding real-world implementation.</p>', 'Teclado Blog', '2024-03-08', 'Blog/Article', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (937, 223, 3, 'reading', 'User Behavior Mining: A Framework for Product Analytics', 'https://link.springer.com/article/10.1007/s12599-023-00848-1', '<p>This academic paper provides theoretical foundations for understanding user behavior analysis through data-driven approaches. It introduces key concepts that underpin analytics tools like Posthog.</p>', 'Business & Information Systems Engineering', '2024-01-05', 'Journal Article', NULL, 35) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (938, 223, 4, 'exercise', 'Set Up Your First Posthog Project', NULL, NULL, NULL, NULL, NULL, '<p>Create a free Posthog Cloud account and complete the following:</p><ol><li><p>Set up a new project and install the JavaScript snippet on a simple HTML page (or use a test site)</p></li><li><p>Configure at least one custom event that tracks a specific user action (button click, form submission, etc.)</p></li><li><p>Navigate the Posthog dashboard to view your captured events</p></li><li><p>Create a simple insight or visualization showing your event data</p></li></ol><p>Document your setup process with screenshots and briefly explain what data your custom event captures and why it''s useful.</p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1231, 300, 3, 'reading', 'Visual Storytelling in the Age of Digital Cinema', 'https://www.worldcat.org/title/cinema-in-the-digital-age/oclc/55673421', '<p><cite index=''9-1:3,9-29:31''>Investigates the transition to digital cinematography, from early digital techniques in Star Wars prequels to the first digital cinematography Oscar in 2009, while acknowledging the ongoing tension with traditional filmmaking approaches</cite></p>', 'Steven Soderbergh', '15/03/2005', 'Book', NULL, 180) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (1232, 300, 4, 'exercise', 'Future of Cinematography: Innovative Storytelling Project', NULL, NULL, NULL, NULL, NULL, '<p>Create a groundbreaking multimedia narrative that pushes the boundaries of contemporary visual storytelling:</p><ol><li><p>Conceptualization:</p></li></ol><ul><li><p>Develop an innovative storytelling concept that leverages at least THREE emerging technologies:</p></li><li><p>Virtual Reality (VR)</p></li><li><p>Augmented Reality (AR)</p></li><li><p>360-degree video</p></li><li><p>Interactive narrative techniques</p></li><li><p>Artificial Intelligence-assisted storytelling</p></li><li><p>Volumetric capture</p></li><li><p>Real-time rendering</p></li></ul><ol><li><p>Project Development:</p></li></ol><ul><li><p>Design a 10-15 minute immersive narrative experience</p></li><li><p>Create a prototype or proof-of-concept</p></li><li><p>Document your creative and technical process</p></li></ul><ol><li><p>Technical Requirements:</p></li></ol><ul><li><p>Must involve at least 2 different media formats</p></li><li><p>Demonstrate innovative use of digital cinematography techniques</p></li><li><p>Include a clear narrative arc or storytelling mechanism</p></li></ul><ol><li><p>Presentation and Distribution:</p></li></ol><ul><li><p>Create a comprehensive project pitch</p></li><li><p>Develop a prototype or working demo</p></li><li><p>Prepare a 5-minute video explaining your concept</p></li><li><p>Share your project in:</p></li><li><p>Film technology forums</p></li><li><p>Digital storytelling communities</p></li><li><p>Experimental film festivals</p></li><li><p>Technology innovation platforms</p></li></ul><p>Bonus Challenges:</p><ul><li><p>Collaborate with professionals from different disciplines</p></li><li><p>Create an open-source version of your narrative framework</p></li><li><p>Document the entire development process as an educational resource</p></li></ul>', NULL) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5417, 2063, 1, 'reading', 'The Apology of Socrates', 'https://example.com/apology', NULL, NULL, NULL, NULL, NULL, 40) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5523, 2264, 1, 'reading', 'werqwer', 'https://www.youtube.com/watch?v=YkphMi7Guuc', '<p>This introductory article covers the fundamental concepts and terminology of werqwer. Read carefully to establish a foundation for the rest of the week.</p>', 'Ty August', '2013-12-12', 'Youtube video', NULL, 20) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5524, 2264, 2, 'reading', 'Core Principles of werqwer', 'https://www.jstor.org/stable/werqwer-principles', '<p>This academic paper explores the core principles that underpin werqwer theory and practice. Focus on the key concepts introduced in the first sections.</p>', 'Academic Journal', '2023-06-10', 'Journal Article', NULL, 25) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5525, 2264, 3, 'reading', 'Getting Started with werqwer', NULL, '<p>A beginner-friendly guide that walks through practical applications of werqwer concepts. Pay attention to the examples provided throughout.</p>', 'Introduction Guide', '2024-03-01', 'Blog/Article', NULL, 18) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5526, 2264, 4, 'exercise', 'Apply Your Understanding of werqwer Fundamentals', NULL, NULL, NULL, NULL, NULL, '<p>Create a simple project that demonstrates your understanding of werqwer basics:</p><ol><li><p>Identify three core concepts from this week''s readings</p></li><li><p>Write a brief explanation (2-3 sentences each) of how these concepts relate to each other</p></li><li><p>Develop one original example that illustrates a practical application of werqwer</p></li><li><p>Reflect on what you found most challenging and what questions remain</p></li></ol><p></p>', 45) ON CONFLICT DO NOTHING;
INSERT INTO steps (id, week_id, position, type, title, url, note, author, creation_date, media_type, prompt_text, estimated_minutes) VALUES (5529, 2285, 1, 'reading', '', NULL, NULL, NULL, NULL, NULL, NULL, 15) ON CONFLICT DO NOTHING;
